{
  "name": "Three.js Master Control",
  "description": "A comprehensive 3D model viewer and post-processing studio. Real-time control over Bloom, Material properties, and Scene settings with dynamic Three.js code generation."
}

export interface BloomSettings {
  intensity: number;
  threshold: number;
  radius: number;
  enabled: boolean;
}

export interface MaterialSettings {
  color: string;
  emissive: string;
  emissiveIntensity: number;
  metalness: number;
  roughness: number;
  wireframe: boolean;
  opacity: number;
  transparent: boolean;
}

export interface SceneSettings {
  exposure: number;
  background: string;
  autoRotate: boolean;
  gridHelper: boolean;
  ambientIntensity: number;
}

export interface AppState {
  bloom: BloomSettings;
  material: MaterialSettings;
  scene: SceneSettings;
}

export type TabType = 'settings' | 'code';

import { AppState } from './types';

export const INITIAL_STATE: AppState = {
  bloom: {
    intensity: 1.5,
    threshold: 0.8,
    radius: 0.4,
    enabled: true,
  },
  material: {
    color: '#3b82f6',
    emissive: '#000000',
    emissiveIntensity: 1.0,
    metalness: 0.6,
    roughness: 0.2,
    wireframe: false,
    opacity: 1.0,
    transparent: false,
  },
  scene: {
    exposure: 1.0,
    background: '#0f172a',
    autoRotate: true,
    gridHelper: true,
    ambientIntensity: 0.5,
  },
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { 
  OrbitControls, 
  PerspectiveCamera, 
  Stage, 
  Grid, 
  Environment,
  ContactShadows,
  Float
} from '@react-three/drei';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import { Settings2, Code, Box, Palette, Sun, Layers } from 'lucide-react';
import { INITIAL_STATE } from './constants';
import { AppState, TabType } from './types';

// Sub-components
import Sidebar from './components/Sidebar';
import CodePanel from './components/CodePanel';
import SceneModel from './components/SceneModel';

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');

  const updateState = <K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => {
    setState(prev => ({
      ...prev,
      [category]: {
        ...prev[category],
        [key]: value
      }
    }));
  };

  return (
    <div className="flex h-screen w-full bg-slate-900 text-slate-100 overflow-hidden font-sans">
      {/* 3D Viewer Area */}
      <main className="relative flex-1 bg-gradient-to-br from-slate-900 to-slate-800">
        <Canvas shadows dpr={[1, 2]}>
          <color attach="background" args={[state.scene.background]} />

          <PerspectiveCamera makeDefault position={[5, 5, 5]} fov={50} />
          <OrbitControls 
            makeDefault 
            autoRotate={state.scene.autoRotate} 
            autoRotateSpeed={0.5} 
            enableDamping 
          />

          <ambientLight intensity={state.scene.ambientIntensity} />
          <Environment preset="city" />

          <Stage environment="city" intensity={0.5} contactShadow={false} adjustCamera={false}>
            <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5}>
              <SceneModel settings={state.material} />
            </Float>
          </Stage>

          <ContactShadows 
            position={[0, -1.5, 0]} 
            opacity={0.4} 
            scale={10} 
            blur={2} 
            far={4} 
          />

          {state.scene.gridHelper && (
            <Grid 
              position={[0, -1.51, 0]} 
              args={[20, 20]} 
              sectionColor="#334155" 
              cellColor="#1e293b" 
              fadeDistance={25} 
            />
          )}

          <EffectComposer disableNormalPass>
            {state.bloom.enabled && (
              <Bloom 
                luminanceThreshold={state.bloom.threshold} 
                mipmapBlur 
                luminanceSmoothing={0.9} 
                intensity={state.bloom.intensity} 
                radius={state.bloom.radius}
              />
            )}
          </EffectComposer>
        </Canvas>

        {/* View overlay UI */}
        <div className="absolute top-6 left-6 pointer-events-none">
          <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-emerald-400">
            Three.js Studio
          </h1>
          <p className="text-slate-400 text-sm">Interactive Material Lab</p>
        </div>

        <div className="absolute bottom-6 left-6 flex items-center gap-4">
          <div className="px-4 py-2 bg-slate-800/80 backdrop-blur-md rounded-lg border border-slate-700/50 flex items-center gap-2 shadow-xl">
            <div className={`w-2 h-2 rounded-full ${state.bloom.enabled ? 'bg-emerald-400 shadow-[0_0_8px_rgba(52,211,153,0.8)]' : 'bg-slate-600'}`} />
            <span className="text-xs font-medium uppercase tracking-wider text-slate-300">Bloom Engine Active</span>
          </div>
        </div>
      </main>

      {/* Control Sidebar */}
      <div className="w-[420px] h-full bg-slate-800/50 backdrop-blur-xl border-l border-slate-700/50 flex flex-col shadow-2xl z-10">
        {/* Tabs */}
        <div className="flex border-b border-slate-700/50">
          <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 flex items-center justify-center gap-2 py-4 transition-all duration-200 border-b-2 ${
              activeTab === 'settings' 
              ? 'bg-slate-800 text-blue-400 border-blue-500' 
              : 'text-slate-500 hover:text-slate-300 border-transparent'
            }`}
          >
            <Settings2 size={18} />
            <span className="text-sm font-semibold uppercase tracking-wider">Properties</span>
          </button>
          <button 
            onClick={() => setActiveTab('code')}
            className={`flex-1 flex items-center justify-center gap-2 py-4 transition-all duration-200 border-b-2 ${
              activeTab === 'code' 
              ? 'bg-slate-800 text-emerald-400 border-emerald-500' 
              : 'text-slate-500 hover:text-slate-300 border-transparent'
            }`}
          >
            <Code size={18} />
            <span className="text-sm font-semibold uppercase tracking-wider">Source Code</span>
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6">
          {activeTab === 'settings' ? (
            <Sidebar state={state} updateState={updateState} />
          ) : (
            <CodePanel state={state} />
          )}
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-slate-700/50 bg-slate-800/80 text-center">
          <p className="text-[10px] text-slate-500 uppercase tracking-widest font-medium">
            Powered by Three.js & React Three Fiber
          </p>
        </div>
      </div>
    </div>
  );
}

import React, { useMemo } from 'react';
import * as THREE from 'three';
import { MaterialSettings } from '../types';

interface SceneModelProps {
  settings: MaterialSettings;
}

const SceneModel: React.FC<SceneModelProps> = ({ settings }) => {
  // Creating complex geometry for interesting lighting
  const geometry = useMemo(() => new THREE.IcosahedronGeometry(1.5, 15), []);

  return (
    <mesh geometry={geometry} castShadow receiveShadow>
      <meshStandardMaterial 
        color={settings.color}
        emissive={settings.emissive}
        emissiveIntensity={settings.emissiveIntensity}
        metalness={settings.metalness}
        roughness={settings.roughness}
        wireframe={settings.wireframe}
        transparent={settings.transparent}
        opacity={settings.opacity}
      />
    </mesh>
  );
};

export default SceneModel;

import React from 'react';
import { AppState } from '../types';
