import React, { useState } from 'react';
import { AppState } from '../types';
import { Copy, Check, Terminal } from 'lucide-react';

interface CodePanelProps {
  state: AppState;
}

const CodePanel: React.FC<CodePanelProps> = ({ state }) => {
  const [copied, setCopied] = useState(false);

  const materialCode = `// Three.js Material Configuration
const material = new THREE.MeshStandardMaterial({
  color: '${state.material.color}',
  metalness: ${state.material.metalness.toFixed(2)},
  roughness: ${state.material.roughness.toFixed(2)},
  emissive: '${state.material.emissive}',
  emissiveIntensity: ${state.material.emissiveIntensity.toFixed(1)},
  wireframe: ${state.material.wireframe},
  transparent: ${state.material.transparent},
  opacity: ${state.material.opacity.toFixed(1)}
});

// Post-Processing Bloom Setup
const bloomEffect = new BloomEffect({
  luminanceThreshold: ${state.bloom.threshold.toFixed(2)},
  intensity: ${state.bloom.intensity.toFixed(1)},
  radius: ${state.bloom.radius.toFixed(2)},
  mipmapBlur: true
});`;

  const handleCopy = () => {
    navigator.clipboard.writeText(materialCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in slide-in-from-right-4 duration-300">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Terminal size={16} className="text-emerald-400" />
          <span className="text-xs font-bold uppercase tracking-widest text-slate-300">Generated Code</span>
        </div>
        <button 
          onClick={handleCopy}
          className="p-2 hover:bg-slate-700 rounded-lg transition-colors text-slate-400 hover:text-white"
          title="Copy to clipboard"
        >
          {copied ? <Check size={16} className="text-emerald-400" /> : <Copy size={16} />}
        </button>
      </div>

      <div className="flex-1 bg-slate-900 rounded-xl border border-slate-700 p-4 overflow-auto fira-code text-sm">
        <pre className="text-emerald-300/90 whitespace-pre-wrap">
          {materialCode.split('\n').map((line, i) => {
            if (line.startsWith('//')) {
              return <div key={i} className="text-slate-500 italic mb-1">{line}</div>;
            }
            const parts = line.split(':');
            if (parts.length === 2) {
              return (
                <div key={i} className="mb-0.5">
                  <span className="text-emerald-500">{parts[0]}</span>
                  <span className="text-slate-400">:</span>
                  <span className="text-blue-300">{parts[1]}</span>
                </div>
              );
            }
            return <div key={i} className="mb-0.5">{line}</div>;
          })}
        </pre>
      </div>

      <div className="mt-6 space-y-4">
        <h4 className="text-[10px] font-bold uppercase tracking-widest text-slate-500">Quick Integration Tip</h4>
        <div className="p-4 bg-slate-800/50 rounded-lg border border-slate-700/50 text-[11px] text-slate-400 leading-relaxed">
          To use this in your Three.js project, ensure you have <code className="text-blue-400">three</code> and <code className="text-blue-400">postprocessing</code> installed. For React projects, the <code className="text-emerald-400">@react-three/fiber</code> ecosystem is recommended for reactive material updates.
        </div>
      </div>
    </div>
  );
};

export default CodePanel;

