export type TabType = 'settings' | 'code';

import React, { useMemo } from 'react';
import * as THREE from 'three';
import { MaterialSettings } from '../types';

interface SceneModelProps {
  settings: MaterialSettings;
}

const SceneModel: React.FC<SceneModelProps> = ({ settings }) => {
  const geometry = useMemo(() => new THREE.IcosahedronGeometry(1.5, 24), []);

  const commonProps = {
    color: settings.color,
    wireframe: settings.wireframe,
    transparent: settings.transparent,
    opacity: settings.opacity,
  };

  const standardProps = {
    ...commonProps,
    emissive: settings.emissive,
    emissiveIntensity: settings.emissiveIntensity,
    metalness: settings.metalness,
    roughness: settings.roughness,
    envMapIntensity: settings.envMapIntensity,
  };

  const physicalProps = {
    ...standardProps,
    clearcoat: settings.clearcoat,
    clearcoatRoughness: settings.clearcoatRoughness,
    transmission: settings.transmission,
    thickness: settings.thickness,
    ior: settings.ior,
    specularIntensity: settings.specularIntensity,
  };

  return (
    <mesh geometry={geometry} castShadow receiveShadow>
      {settings.type === 'basic' && <meshBasicMaterial {...commonProps} />}
      {settings.type === 'phong' && <meshPhongMaterial {...commonProps} emissive={settings.emissive} />}
      {settings.type === 'standard' && <meshStandardMaterial {...standardProps} />}
      {settings.type === 'physical' && <meshPhysicalMaterial {...physicalProps} />}
    </mesh>
  );
};

export default SceneModel;

import React, { useState } from 'react';
import { Canvas } from '@react-three/fiber';
import { 
  OrbitControls, 
  PerspectiveCamera, 
  Stage, 
  Grid, 
  Environment,
  ContactShadows,
  Float
} from '@react-three/drei';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import { Settings2, Code } from 'lucide-react';
import { INITIAL_STATE } from './constants';
import { AppState, TabType } from './types';

// Sub-components
import Sidebar from './components/Sidebar';
import CodePanel from './components/CodePanel';
import SceneModel from './components/SceneModel';

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');

  const updateState = <K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => {
    setState(prev => ({
      ...prev,
      [category]: {
        ...prev[category],
        [key]: value
      }
    }));
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      {/* 3D Viewer Area */}
      <main className="relative flex-1 bg-black">
        <Canvas shadows dpr={[1, 2]} gl={{ antialias: true, stencil: false }}>
          <color attach="background" args={[state.scene.background]} />

          <PerspectiveCamera makeDefault position={[5, 5, 5]} fov={45} />
          <OrbitControls 
            makeDefault 
            autoRotate={state.scene.autoRotate} 
            autoRotateSpeed={0.5} 
            enableDamping 
          />

          <ambientLight intensity={state.scene.ambientIntensity} />
          <Environment preset="studio" />

          <Stage environment="studio" intensity={0.5} contactShadow={false} adjustCamera={false}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={0.5}>
              <SceneModel settings={state.material} />
            </Float>
          </Stage>

          {state.scene.contactShadows && (
            <ContactShadows 
              position={[0, -1.5, 0]} 
              opacity={state.scene.shadowOpacity} 
              scale={12} 
              blur={state.scene.shadowBlur} 
              far={4} 
            />
          )}

          {state.scene.gridHelper && (
            <Grid 
              position={[0, -1.51, 0]} 
              args={[20, 20]} 
              sectionColor="#1e293b" 
              cellColor="#0f172a" 
              fadeDistance={30} 
            />
          )}

          <EffectComposer multisampling={4}>
            {state.bloom.enabled && (
              <Bloom 
                luminanceThreshold={state.bloom.threshold} 
                mipmapBlur 
                intensity={state.bloom.intensity} 
                radius={state.bloom.radius}
              />
            )}
          </EffectComposer>
        </Canvas>

        {/* View overlay UI */}
        <div className="absolute top-6 left-6 pointer-events-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400">
            Three.js Studio Pro
          </h1>
          <p className="text-slate-500 text-xs tracking-widest uppercase mt-1">Advanced Render Control</p>
        </div>
      </main>

      {/* Control Sidebar */}
      <div className="w-[440px] h-full bg-slate-900/90 backdrop-blur-2xl border-l border-slate-800 flex flex-col shadow-2xl z-10">
        {/* Tabs */}
        <div className="flex border-b border-slate-800">
          <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 flex items-center justify-center gap-2 py-5 transition-all duration-200 border-b-2 ${
              activeTab === 'settings' 
              ? 'bg-slate-900 text-blue-400 border-blue-500' 
              : 'text-slate-500 hover:text-slate-300 border-transparent'
            }`}
          >
            <Settings2 size={16} />
            <span className="text-[11px] font-bold uppercase tracking-widest">Properties</span>
          </button>
          <button 
            onClick={() => setActiveTab('code')}
            className={`flex-1 flex items-center justify-center gap-2 py-5 transition-all duration-200 border-b-2 ${
              activeTab === 'code' 
              ? 'bg-slate-900 text-emerald-400 border-emerald-500' 
              : 'text-slate-500 hover:text-slate-300 border-transparent'
            }`}
          >
            <Code size={16} />
            <span className="text-[11px] font-bold uppercase tracking-widest">Live Code</span>
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' ? (
            <Sidebar state={state} updateState={updateState} />
          ) : (
            <CodePanel state={state} />
          )}
        </div>
      </div>
    </div>
  );
}

