import React, { useMemo } from 'react';
import * as THREE from 'three';
import { MaterialSettings } from '../types';

interface SceneModelProps {
  settings: MaterialSettings;
}

const SceneModel: React.FC<SceneModelProps> = ({ settings }) => {
  const geometry = useMemo(() => new THREE.IcosahedronGeometry(1.5, 24), []);

  const commonProps = {
    color: settings.color,
    wireframe: settings.wireframe,
    transparent: settings.transparent,
    opacity: settings.opacity,
  };

  const standardProps = {
    ...commonProps,
    emissive: settings.emissive,
    emissiveIntensity: settings.emissiveIntensity,
    metalness: settings.metalness,
    roughness: settings.roughness,
    envMapIntensity: settings.envMapIntensity,
  };

  const physicalProps = {
    ...standardProps,
    clearcoat: settings.clearcoat,
    clearcoatRoughness: settings.clearcoatRoughness,
    transmission: settings.transmission,
    thickness: settings.thickness,
    ior: settings.ior,
    specularIntensity: settings.specularIntensity,
  };

  return (
    // @ts-ignore: mesh is a valid R3F intrinsic element
    <mesh geometry={geometry} castShadow receiveShadow>
      {/* @ts-ignore: meshBasicMaterial is a valid R3F intrinsic element */}
      {settings.type === 'basic' && <meshBasicMaterial {...commonProps} />}
      {/* @ts-ignore: meshPhongMaterial is a valid R3F intrinsic element */}
      {settings.type === 'phong' && <meshPhongMaterial {...commonProps} emissive={settings.emissive} />}
      {/* @ts-ignore: meshStandardMaterial is a valid R3F intrinsic element */}
      {settings.type === 'standard' && <meshStandardMaterial {...standardProps} />}
      {/* @ts-ignore: meshPhysicalMaterial is a valid R3F intrinsic element */}
      {settings.type === 'physical' && <meshPhysicalMaterial {...physicalProps} />}
    {/* @ts-ignore */}
    </mesh>
  );
};

export default SceneModel;

