  emissiveIntensity: number;
  metalness: number;
  roughness: number;
  wireframe: boolean;
  opacity: number;
  transparent: boolean;
  envMapIntensity: number;
  // Physical Material specific
  clearcoat: number;
  clearcoatRoughness: number;
  transmission: number;
  thickness: number;
  ior: number;
  specularIntensity: number;
}

export interface SceneSettings {
  exposure: number;
  background: string;
  autoRotate: boolean;
  gridHelper: boolean;
  ambientIntensity: number;
  contactShadows: boolean;
  shadowOpacity: number;
  shadowBlur: number;
  showPlane: boolean;
