  OrbitControls, 
  PerspectiveCamera, 
  Stage, 
  Grid, 
  Environment,
  ContactShadows,
  Float,
  SoftShadows
} from '@react-three/drei';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import { Settings2, Code, Upload } from 'lucide-react';
import { INITIAL_STATE } from './constants';
import { AppState, TabType } from './types';

// Sub-components
import Sidebar from './components/Sidebar';
import CodePanel from './components/CodePanel';
import SceneModel from './components/SceneModel';

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');
  const [customModel, setCustomModel] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const updateState = useCallback(<K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => {
    setState(prev => ({
      ...prev,
      [category]: {
        ...prev[category],
        [key]: value
      }
    }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);
      setCustomModel(url);
      updateState('scene', 'modelType', 'custom');
    }
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      {/* Hidden file input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        className="hidden" 
        accept=".glb,.gltf,.obj"
      />

      {/* 3D Viewer Area */}
      <main className="relative flex-1 bg-black">
        <Canvas shadows dpr={[1, 2]} gl={{ antialias: true }}>
          <SoftShadows size={25} samples={10} focus={0} />
          {/* @ts-ignore */}
          <color attach="background" args={[state.scene.background]} />

          <PerspectiveCamera makeDefault position={[5, 5, 5]} fov={45} />
          <OrbitControls makeDefault autoRotate={state.scene.autoRotate} autoRotateSpeed={0.5} enableDamping />

          {/* @ts-ignore */}
          <ambientLight intensity={state.scene.ambientIntensity} />
          <Environment preset="studio" />

          <Stage environment="studio" intensity={0.5} contactShadow={false} adjustCamera={false}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <SceneModel settings={state.material} modelType={state.scene.modelType} customUrl={customModel} override={state.scene.overrideMaterials} />
