            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <SceneModel settings={state.material} modelType={state.scene.modelType} customUrl={customModel} override={state.scene.overrideMaterials} />
            </Float>
          </Stage>

          {state.scene.showPlane && (
            /* @ts-ignore */
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.5, 0]} receiveShadow>
              {/* @ts-ignore */}
              <planeGeometry args={[100, 100]} />
              {/* @ts-ignore */}
              <meshStandardMaterial color={state.scene.background} roughness={1} metalness={0} />
            </mesh>
          )}

          {state.scene.contactShadows && (
            <ContactShadows 
              position={[0, -1.5, 0]} 
              opacity={state.scene.shadowOpacity} 
              scale={15} 
              blur={state.scene.shadowBlur} 
              far={5} 
            />
          )}

          {state.scene.gridHelper && (
            <Grid 
              position={[0, -1.51, 0]} 
              args={[20, 20]} 
              sectionColor="#1e293b" 
              cellColor="#0f172a" 
              fadeDistance={30} 
            />
          )}

          <EffectComposer multisampling={4}>
            {state.bloom.enabled && (
              <Bloom luminanceThreshold={state.bloom.threshold} mipmapBlur intensity={state.bloom.intensity} radius={state.bloom.radius} />
            )}
          </EffectComposer>
        </Canvas>

        {/* View overlay UI */}
        <div className="absolute top-6 left-6 pointer-events-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400">
            Three.js Studio Pro
          </h1>
          <p className="text-slate-500 text-xs tracking-widest uppercase mt-1">
            {state.scene.modelType === 'custom' ? 'Custom Asset Loaded' : 'Built-in Asset View'}
          </p>
        </div>

        <button 
          onClick={() => fileInputRef.current?.click()}
          className="absolute bottom-6 left-6 p-4 bg-blue-600 hover:bg-blue-500 rounded-full shadow-2xl transition-all hover:scale-110 active:scale-95 group"
          title="Upload GLB/OBJ"
        >
          <Upload size={24} className="text-white" />
        </button>
      </main>

      {/* Control Sidebar */}
      <div className="w-[440px] h-full bg-slate-900/95 backdrop-blur-2xl border-l border-slate-800 flex flex-col shadow-2xl z-10 overflow-hidden">
        <div className="flex border-b border-slate-800">
          <button onClick={() => setActiveTab('settings')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 ${activeTab === 'settings' ? 'text-blue-400 border-blue-500 bg-slate-800/20' : 'text-slate-500 border-transparent'}`}>
            <Settings2 size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Properties</span>
          </button>
          <button onClick={() => setActiveTab('code')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 ${activeTab === 'code' ? 'text-emerald-400 border-emerald-500 bg-slate-800/20' : 'text-slate-500 border-transparent'}`}>
            <Code size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Live Code</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' ? <Sidebar state={state} updateState={updateState} /> : <CodePanel state={state} />}
