  if (modelType === 'custom' && customObject) {
    // @ts-ignore
    return <primitive object={customObject} scale={1.2} />;
  }

  /* @ts-ignore */
  return (
    // @ts-ignore
    <mesh geometry={geometries[modelType as keyof typeof geometries]} castShadow receiveShadow>
      {/* @ts-ignore */}
      <primitive object={material} attach="material" />
    </mesh>
  );
};

