import React, { useMemo, useEffect } from 'react';
import * as THREE from 'three';
import { useGLTF } from '@react-three/drei';
import { OBJLoader } from 'three/examples/jsm/loaders/OBJLoader';
import { useLoader } from '@react-three/fiber';
import { MaterialSettings, ModelType } from '../types';

interface SceneModelProps {
  settings: MaterialSettings;
  modelType: ModelType;
  customUrl: string | null;
  override: boolean;
}

// Fix for missing JSX intrinsic elements types in Three.js/R3F environment
const Mesh = 'mesh' as any;
const Primitive = 'primitive' as any;

const SceneModel: React.FC<SceneModelProps> = ({ settings, modelType, customUrl, override }) => {
  const geometries = {
    icosahedron: useMemo(() => new THREE.IcosahedronGeometry(1, 24), []),
    sphere: useMemo(() => new THREE.SphereGeometry(1, 64, 64), []),
    box: useMemo(() => new THREE.BoxGeometry(1.5, 1.5, 1.5), []),
    torus: useMemo(() => new THREE.TorusGeometry(0.8, 0.3, 32, 100), []),
    cylinder: useMemo(() => new THREE.CylinderGeometry(0.8, 0.8, 1.8, 32), []),
    cone: useMemo(() => new THREE.ConeGeometry(0.8, 1.8, 32), []),
    knot: useMemo(() => new THREE.TorusKnotGeometry(0.6, 0.2, 128, 32), []),
  };

  let customObject: any = null;
  if (modelType === 'custom' && customUrl) {
    try {
      if (customUrl.toLowerCase().endsWith('.obj')) {
        // @ts-ignore
        customObject = useLoader(OBJLoader, customUrl);
      } else {
        // @ts-ignore
        const { scene } = useGLTF(customUrl);
        customObject = scene;
      }
    } catch (e) {
      console.error("Failed to load model:", e);
    }
  }

  const material = useMemo(() => {
    // Auto-enable transparency if properties require it
    const isTransparent = settings.transparent || settings.opacity < 1 || settings.transmission > 0;

    const commonProps = {
      color: settings.color,
      wireframe: settings.wireframe,
      transparent: isTransparent,
      opacity: settings.opacity,
    };

    switch (settings.type) {
      case 'basic': 
        return new THREE.MeshBasicMaterial(commonProps);
      case 'phong': 
        return new THREE.MeshPhongMaterial({ 
          ...commonProps, 
          emissive: settings.emissive,
          emissiveIntensity: settings.emissiveIntensity,
          specular: settings.specular,
          shininess: settings.shininess
        });
      case 'physical': 
        return new THREE.MeshPhysicalMaterial({
          ...commonProps,
          emissive: settings.emissive,
          emissiveIntensity: settings.emissiveIntensity,
          metalness: settings.metalness,
          roughness: settings.roughness,
          envMapIntensity: settings.envMapIntensity,
          clearcoat: settings.clearcoat,
          clearcoatRoughness: settings.clearcoatRoughness,
          transmission: settings.transmission,
          thickness: settings.thickness,
          ior: settings.ior,
          specularIntensity: settings.specularIntensity,
        });
      default: 
        return new THREE.MeshStandardMaterial({
          ...commonProps,
          emissive: settings.emissive,
          emissiveIntensity: settings.emissiveIntensity,
          metalness: settings.metalness,
          roughness: settings.roughness,
          envMapIntensity: settings.envMapIntensity,
        });
    }
  }, [settings]);

  useEffect(() => {
    if (customObject) {
      const box = new THREE.Box3().setFromObject(customObject);
      const size = new THREE.Vector3();
      box.getSize(size);
      const maxDim = Math.max(size.x, size.y, size.z);
      const scale = maxDim > 0 ? 2 / maxDim : 1;
      customObject.scale.setScalar(scale);

      const center = new THREE.Vector3();
      box.getCenter(center);
      customObject.position.sub(center.multiplyScalar(scale));

      customObject.traverse((child: any) => {
        if (child.isMesh) {
          if (override) child.material = material;
          child.castShadow = true;
          child.receiveShadow = true;
        }
      });
    }
  }, [customObject, material, override]);

  if (modelType === 'custom' && customObject) {
    /* Fix: Use Primitive constant to avoid JSX intrinsic element error */
    return <Primitive object={customObject} />;
  }

  /* Fix: Use Mesh and Primitive constants to avoid JSX intrinsic element error */
  return (
    <Mesh geometry={geometries[modelType as keyof typeof geometries]} castShadow receiveShadow>
      <Primitive object={material} attach="material" />
    </Mesh>
  );
};

export default SceneModel;

import React from 'react';
import { AppState, MaterialSettings, MaterialType, ModelType } from '../types';
