    category: K,
    key: S,
    value: AppState[K][S]
  ) => {
    setState(prev => ({
      ...prev,
      [category]: category === 'materials' 
        ? { ...prev.materials, [state.selectedMaterialId]: { ...prev.materials[state.selectedMaterialId], [key]: value } }
        : { ...prev[category], [key]: value }
    }));
  }, [state.selectedMaterialId]);

  // Special update for Top-level state like selectedMaterialId
  const setTopState = useCallback(<K extends keyof AppState>(key: K, value: AppState[K]) => {
    setState(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);
      setCustomModel(url);

      // We will perform the scan inside the SceneModel or use useGLTF here to pre-scan
      setTopState('scene', { ...state.scene, modelType: 'custom' });
    }
  };

  // Callback from SceneModel when materials are discovered
  const onMaterialsDiscovered = useCallback((discoveredMaterials: string[]) => {
    setState(prev => {
      const newMaterials = { ...prev.materials };
      let firstId = prev.selectedMaterialId;

      discoveredMaterials.forEach((name, index) => {
        const id = `mat-${name || index}`;
        if (!newMaterials[id]) {
          newMaterials[id] = createDefaultMaterial(id, name || `Material ${index + 1}`);
        }
        if (index === 0 && prev.selectedMaterialId === 'default-material') firstId = id;
      });

      return {
        ...prev,
        materials: newMaterials,
        selectedMaterialId: firstId
      };
    });
  }, []);

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        className="hidden" 
        accept=".glb,.gltf,.obj"
      />

      <main className="relative flex-1 bg-black">
        <Canvas 
          shadows={{ type: THREE.PCFSoftShadowMap }} 
          dpr={[1, 2]} 
          gl={{ antialias: true, alpha: false, stencil: false }}
        >
          <Color attach="background" args={[state.scene.background]} />

          <PerspectiveCamera makeDefault position={[4, 3, 4]} fov={50} />
          <OrbitControls 
            makeDefault 
            autoRotate={state.scene.autoRotate} 
            autoRotateSpeed={0.5} 
            enableDamping 
          />

          <AmbientLight intensity={state.scene.ambientIntensity} />
          <DirectionalLight 
            position={[5, 10, 5]} 
            intensity={1.5} 
            castShadow 
            shadow-mapSize={[1024, 1024]}
          >
            <OrthographicCamera attach="shadow-camera" args={[-10, 10, 10, -10, 0.5, 30]} />
          </DirectionalLight>

          <Environment preset="city" />

          <Group position={[0, 0, 0]}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <Suspense fallback={null}>
                <SceneModel 
                  materials={state.materials} 
                  modelType={state.scene.modelType} 
                  customUrl={customModel} 
                  override={state.scene.overrideMaterials}
                  onMaterialsFound={onMaterialsDiscovered}
                />
              </Suspense>
            </Float>
          </Group>

          {state.scene.showPlane && (
            <MeshComp rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.0, 0]} receiveShadow>
              <PlaneGeometry args={[100, 100]} />
              <MeshStandardMaterial 
                color={state.scene.planeColor} 
                roughness={state.scene.planeRoughness} 
