      });
    }
  }, [customScene, nativeMaterials, override, modelType]);

  if (modelType === 'custom' && customScene) {
    return <Primitive object={customScene} scale={2} />;
  }

  // Fallback for internal geometries
  const activeSettings = Object.values(materials)[0];
  // Handle case where materials might be empty initially
  const fallbackMaterial = useMemo(() => activeSettings ? createMaterial(activeSettings) : new THREE.MeshStandardMaterial(), [activeSettings, matcapTexture]);

  return (
    <MeshComp 
      geometry={geometries[modelType as keyof typeof geometries] || geometries.icosahedron} 
      castShadow 
      receiveShadow
    >
      <Primitive object={fallbackMaterial} attach="material" />
    </MeshComp>
  );
};

