            if (Array.isArray(child.material)) {
              child.material = child.material.map((orig: any) => {
                const name = orig && (orig as THREE.Material).name;
                return (name && nativeMaterials[name]) || orig;
              });
            } else if (child.material) {
              const name = (child.material as THREE.Material).name;
              const matched = name && nativeMaterials[name];
              if (matched) child.material = matched;
            }
          }
        }
      });
    }
  }, [scene, nativeMaterials, override]);

  return <Primitive object={scene} scale={2} />;
};

const SceneModel: React.FC<SceneModelProps> = ({ materials, modelType, customUrl, override, onMaterialsFound }) => {
  // Use a different matcap ID that is more likely to be stable (numeric index 0 is a safe standard)
  // The string ID used previously was throwing a 404/undefined error on some CDNs.
  const [matcapTexture] = useMatcapTexture(0, 256);

  const geometries = {
    box: useMemo(() => new THREE.BoxGeometry(1, 1, 1), []),
    sphere: useMemo(() => new THREE.SphereGeometry(0.7, 64, 64), []),
    torus: useMemo(() => new THREE.TorusGeometry(0.5, 0.2, 32, 100), []),
    cylinder: useMemo(() => new THREE.CylinderGeometry(0.5, 0.5, 1, 32), []),
    cone: useMemo(() => new THREE.ConeGeometry(0.5, 1, 32), []),
    knot: useMemo(() => new THREE.TorusKnotGeometry(0.4, 0.15, 128, 32), []),
    icosahedron: useMemo(() => new THREE.IcosahedronGeometry(0.8, 15), []),
  };

  const createMaterial = (settings: MaterialSettings) => {
    const isTransparent = settings.opacity < 1 || settings.transmission > 0 || settings.transparent;
    const baseProps: any = {
      color: new THREE.Color(settings.color),
      wireframe: settings.wireframe,
      transparent: isTransparent,
      opacity: settings.opacity,
      side: THREE.DoubleSide,
    };

    if (['phong', 'lambert', 'standard', 'physical'].includes(settings.type)) {
      baseProps.emissive = new THREE.Color(settings.emissive);
      baseProps.emissiveIntensity = settings.emissiveIntensity;
    }

    switch (settings.type) {
      case 'basic': return new THREE.MeshBasicMaterial(baseProps);
      case 'lambert': return new THREE.MeshLambertMaterial(baseProps);
      case 'phong': return new THREE.MeshPhongMaterial({ 
        ...baseProps, 
        specular: new THREE.Color(settings.specular), 
        shininess: settings.shininess 
      });
      case 'toon': return new THREE.MeshToonMaterial(baseProps);
      case 'normal': return new THREE.MeshNormalMaterial({ wireframe: settings.wireframe });
      case 'depth': return new THREE.MeshDepthMaterial({ wireframe: settings.wireframe });
      case 'matcap': return new THREE.MeshMatcapMaterial({ ...baseProps, matcap: matcapTexture });
      case 'physical': return new THREE.MeshPhysicalMaterial({
        ...baseProps,
        metalness: settings.metalness,
        roughness: settings.roughness,
        clearcoat: settings.clearcoat,
        clearcoatRoughness: settings.clearcoatRoughness,
        transmission: settings.transmission,
        thickness: settings.thickness,
        ior: settings.ior,
        envMapIntensity: settings.envMapIntensity
      });
      case 'standard':
      default:
        return new THREE.MeshStandardMaterial({ 
          ...baseProps, 
          metalness: settings.metalness, 
          roughness: settings.roughness, 
          envMapIntensity: settings.envMapIntensity 
        });
    }
  };

  // Build the library of native materials based on current UI state
  const nativeMaterials = useMemo(() => {
    const map: Record<string, THREE.Material> = {};
    (Object.entries(materials) as [string, MaterialSettings][]).forEach(([_, settings]) => {
      map[settings.name] = createMaterial(settings);
    });
    return map;
  }, [materials, matcapTexture]);

  // Handle custom model loading separately to avoid invalid hook arguments
  if (modelType === 'custom' && customUrl) {
    return (
      <CustomModelInstance 
        url={customUrl} 
        onMaterialsFound={onMaterialsFound}
        nativeMaterials={nativeMaterials}
        override={override}
      />
    );
  }

  // Fallback for internal geometries
  // Explicitly casting to MaterialSettings | undefined to resolve 'unknown' type error on line 170
  const activeSettings = Object.values(materials)[0] as MaterialSettings | undefined;
  const fallbackMaterial = useMemo(() => 
    activeSettings ? createMaterial(activeSettings) : new THREE.MeshStandardMaterial()
  , [activeSettings, matcapTexture]);

  return (
    <MeshComp 
      geometry={geometries[modelType as keyof typeof geometries] || geometries.icosahedron} 
      castShadow 
      receiveShadow
    >
      <Primitive object={fallbackMaterial} attach="material" />
    </MeshComp>
  );
};

export default SceneModel;

import React, { useState, useCallback, useRef, Suspense, useTransition } from 'react';
import { Canvas } from '@react-three/fiber';
import * as THREE from 'three';
import { 
  OrbitControls, 
  PerspectiveCamera, 
  Grid, 
  Environment,
  ContactShadows,
  Float,
  BakeShadows
} from '@react-three/drei';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import { Settings2, Code, Upload, Loader2, Package } from 'lucide-react';
import { INITIAL_STATE, createDefaultMaterial } from './constants';
import { AppState, TabType } from './types';

// Sub-components
import Sidebar from './components/Sidebar';
import CodePanel from './components/CodePanel';
import SceneModel from './components/SceneModel';

const AmbientLight = 'ambientLight' as any;
const DirectionalLight = 'directionalLight' as any;
const OrthographicCamera = 'orthographicCamera' as any;
const Group = 'group' as any;
const MeshComp = 'mesh' as any;
const PlaneGeometry = 'planeGeometry' as any;
const MeshStandardMaterial = 'meshStandardMaterial' as any;
const Color = 'color' as any;

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');
  const [customModel, setCustomModel] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const updateState = useCallback(<K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => {
    // If the change might trigger a suspension (like changing material type to matcap)
    // we wrap it in a transition to satisfy React 19.
    const update = () => {
      setState(prev => ({
        ...prev,
        [category]: category === 'materials' 
          ? { ...prev.materials, [state.selectedMaterialId]: { ...prev.materials[state.selectedMaterialId], [key]: value } }
          : { ...prev[category], [key]: value }
      }));
    };

    if (key === 'type' || key === 'modelType') {
      startTransition(update);
    } else {
      update();
    }
  }, [state.selectedMaterialId]);

  const setTopState = useCallback(<K extends keyof AppState>(key: K, value: AppState[K]) => {
    setState(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);

      // CRITICAL: Wrapping updates that cause suspension in startTransition for React 19
      startTransition(() => {
        setCustomModel(url);
        setState(prev => ({
          ...prev,
          scene: { ...prev.scene, modelType: 'custom' }
        }));
      });
    }
  };

  const onMaterialsDiscovered = useCallback((discoveredMaterials: string[]) => {
    // This update is usually triggered by an effect in a suspending component
    setState(prev => {
      const newMaterials = { ...prev.materials };
      let firstId = prev.selectedMaterialId;

      discoveredMaterials.forEach((name, index) => {
        const id = `mat-${name || index}`;
        if (!newMaterials[id]) {
          newMaterials[id] = createDefaultMaterial(id, name || `Material ${index + 1}`);
        }
        if (index === 0 && (prev.selectedMaterialId === 'default-material' || !prev.materials[prev.selectedMaterialId])) {
          firstId = id;
        }
      });

      return {
        ...prev,
        materials: newMaterials,
        selectedMaterialId: firstId
      };
    });
  }, []);

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        className="hidden" 
        accept=".glb,.gltf,.obj"
      />

      <main className="relative flex-1 bg-black">
        {isPending && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-50 pointer-events-none">
            <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
          </div>
        )}

        <Canvas 
          shadows={{ type: THREE.PCFSoftShadowMap }} 
          dpr={[1, 2]} 
          gl={{ antialias: true, alpha: false, stencil: false }}
        >
          <Color attach="background" args={[state.scene.background]} />

          <PerspectiveCamera makeDefault position={[4, 3, 4]} fov={50} />
          <OrbitControls 
            makeDefault 
            autoRotate={state.scene.autoRotate} 
            autoRotateSpeed={0.5} 
            enableDamping 
          />

          <AmbientLight intensity={state.scene.ambientIntensity} />
          <DirectionalLight 
            position={[5, 10, 5]} 
            intensity={1.5} 
            castShadow 
            shadow-mapSize={[1024, 1024]}
          >
            <OrthographicCamera attach="shadow-camera" args={[-10, 10, 10, -10, 0.5, 30]} />
          </DirectionalLight>

          <Environment preset="city" />

          <Group position={[0, 0, 0]}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <Suspense fallback={null}>
                <SceneModel 
                  materials={state.materials} 
                  modelType={state.scene.modelType} 
                  customUrl={customModel} 
                  override={state.scene.overrideMaterials}
                  onMaterialsFound={onMaterialsDiscovered}
                />
              </Suspense>
            </Float>
          </Group>

          {state.scene.showPlane && (
            <MeshComp rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.0, 0]} receiveShadow>
              <PlaneGeometry args={[100, 100]} />
              <MeshStandardMaterial 
                color={state.scene.planeColor} 
                roughness={state.scene.planeRoughness} 
                metalness={0.1} 
                transparent={state.scene.planeOpacity < 1}
                opacity={state.scene.planeOpacity}
              />
            </MeshComp>
          )}

          {state.scene.contactShadows && (
            <ContactShadows 
              position={[0, -0.99, 0]} 
              opacity={state.scene.shadowOpacity} 
              scale={15} 
              blur={state.scene.shadowBlur} 
              far={3} 
            />
          )}

          {state.scene.gridHelper && state.scene.showPlane && (
            <Grid 
              position={[0, -0.995, 0]} 
              args={[20, 20]} 
              sectionColor="#cbd5e1" 
              cellColor="#94a3b8" 
              fadeDistance={25} 
              infiniteGrid
            />
          )}

          <EffectComposer multisampling={4}>
            {state.bloom.enabled && (
              <Bloom 
                luminanceThreshold={state.bloom.threshold} 
                mipmapBlur 
                intensity={state.bloom.intensity} 
                radius={state.bloom.radius} 
              />
            )}
          </EffectComposer>
          <BakeShadows />
        </Canvas>

        <div className="absolute top-6 left-6 pointer-events-none select-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400">
            Three.js Studio Pro
          </h1>
          <p className="text-slate-500 text-[10px] tracking-[0.3em] uppercase mt-1 flex items-center gap-2">
            <Package size={10} />
            {state.scene.modelType === 'custom' ? 'Complex Multi-Mesh Asset' : 'Internal Geometry'}
          </p>
        </div>

        <button 
          onClick={() => fileInputRef.current?.click()}
          className="absolute bottom-6 left-6 p-4 bg-blue-600 hover:bg-blue-500 rounded-full shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all hover:scale-110 active:scale-95 group"
          title="Upload GLB/OBJ"
        >
          <Upload size={24} className="text-white" />
        </button>
      </main>

      <div className="w-[440px] h-full bg-slate-900/98 backdrop-blur-xl border-l border-slate-800 flex flex-col shadow-2xl z-10 overflow-hidden">
        <div className="flex border-b border-slate-800">
          <button onClick={() => setActiveTab('settings')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 ${activeTab === 'settings' ? 'text-blue-400 border-blue-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}>
            <Settings2 size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Properties</span>
          </button>
          <button onClick={() => setActiveTab('code')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 ${activeTab === 'code' ? 'text-emerald-400 border-emerald-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}>
            <Code size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Live Code</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' ? (
            <Sidebar 
              state={state} 
              updateState={updateState} 
              setSelectedMaterialId={(id) => setTopState('selectedMaterialId', id)}
            />
          ) : (
            <CodePanel state={state} />
          )}
        </div>
      </div>
    </div>
  );
}

import React, { useMemo, useEffect } from 'react';
import * as THREE from 'three';
import { useGLTF, useMatcapTexture } from '@react-three/drei';
import { MaterialSettings, ModelType } from '../types';

interface SceneModelProps {
  materials: Record<string, MaterialSettings>;
  modelType: ModelType;
  customUrl: string | null;
  override: boolean;
  onMaterialsFound?: (names: string[]) => void;
}

const MeshComp = 'mesh' as any;
const Primitive = 'primitive' as any;

/**
 * Separated component to handle custom model loading.
 * This prevents the 'useGLTF' hook from being called with an empty string
 * when the user is viewing built-in geometries.
 */
const CustomModelInstance = ({ 
  url, 
  onMaterialsFound, 
  nativeMaterials, 
  override 
}: { 
  url: string, 
  onMaterialsFound?: (names: string[]) => void,
  nativeMaterials: Record<string, THREE.Material>,
  override: boolean
}) => {
  const { scene } = useGLTF(url) as any;

  // Scan for materials only when the scene is loaded/changed
  useEffect(() => {
    if (scene && onMaterialsFound) {
      const foundNames = new Set<string>();
      scene.traverse((child: any) => {
        if (child.isMesh) {
          const mats = Array.isArray(child.material) ? child.material : [child.material];
          mats.forEach((m: any) => {
            if (m && m.name) foundNames.add(m.name);
          });
        }
      });
      if (foundNames.size > 0) {
        onMaterialsFound(Array.from(foundNames));
      }
    }
  }, [scene, onMaterialsFound]);

  // Apply visual settings and overrides
  useEffect(() => {
    if (scene) {
      scene.traverse((child: any) => {
        if (child.isMesh) {
          child.castShadow = true;
          child.receiveShadow = true;

          if (override) {
            if (Array.isArray(child.material)) {
              child.material = child.material.map((orig: any) => {
                const name = orig && (orig as THREE.Material).name;
                return (name && nativeMaterials[name]) || orig;
              });
            } else if (child.material) {
              const name = (child.material as THREE.Material).name;
              const matched = name && nativeMaterials[name];
              if (matched) child.material = matched;
            }
          }
        }
      });
    }
  }, [scene, nativeMaterials, override]);

  return <Primitive object={scene} scale={2} />;
};

const SceneModel: React.FC<SceneModelProps> = ({ materials, modelType, customUrl, override, onMaterialsFound }) => {
  // Matcaps suspend. React 19 requires state changes leading here to be wrapped in startTransition.
  const [matcapTexture] = useMatcapTexture(0, 256);

  const createMaterial = (settings: MaterialSettings) => {
    const isTransparent = settings.opacity < 1 || settings.transmission > 0 || settings.transparent;
    const baseProps: any = {
      color: new THREE.Color(settings.color),
      wireframe: settings.wireframe,
      transparent: isTransparent,
      opacity: settings.opacity,
      side: THREE.DoubleSide,
    };

    if (['phong', 'lambert', 'standard', 'physical'].includes(settings.type)) {
      baseProps.emissive = new THREE.Color(settings.emissive);
      baseProps.emissiveIntensity = settings.emissiveIntensity;
    }

    switch (settings.type) {
      case 'basic': return new THREE.MeshBasicMaterial(baseProps);
      case 'lambert': return new THREE.MeshLambertMaterial(baseProps);
      case 'phong': return new THREE.MeshPhongMaterial({ 
        ...baseProps, 
        specular: new THREE.Color(settings.specular), 
        shininess: settings.shininess 
      });
      case 'toon': return new THREE.MeshToonMaterial(baseProps);
      case 'normal': return new THREE.MeshNormalMaterial({ wireframe: settings.wireframe });
      case 'depth': return new THREE.MeshDepthMaterial({ wireframe: settings.wireframe });
      case 'matcap': return new THREE.MeshMatcapMaterial({ ...baseProps, matcap: matcapTexture });
      case 'physical': return new THREE.MeshPhysicalMaterial({
        ...baseProps,
        metalness: settings.metalness,
        roughness: settings.roughness,
        clearcoat: settings.clearcoat,
        clearcoatRoughness: settings.clearcoatRoughness,
        transmission: settings.transmission,
        thickness: settings.thickness,
        ior: settings.ior,
        envMapIntensity: settings.envMapIntensity
      });
      case 'standard':
      default:
        return new THREE.MeshStandardMaterial({ 
          ...baseProps, 
          metalness: settings.metalness, 
          roughness: settings.roughness, 
          envMapIntensity: settings.envMapIntensity 
        });
    }
  };

  // Build the library of native materials based on current UI state
  const nativeMaterials = useMemo(() => {
    const map: Record<string, THREE.Material> = {};
    (Object.entries(materials) as [string, MaterialSettings][]).forEach(([_, settings]) => {
      map[settings.name] = createMaterial(settings);
    });
    return map;
  }, [materials, matcapTexture]);

  // Handle custom model loading separately to avoid invalid hook arguments
  if (modelType === 'custom' && customUrl) {
    return (
      <CustomModelInstance 
        url={customUrl} 
        onMaterialsFound={onMaterialsFound}
        nativeMaterials={nativeMaterials}
        override={override}
      />
    );
  }

  // Fallback for internal geometries
  const activeSettings = (Object.values(materials)[0] || materials['default-material']) as MaterialSettings | undefined;

  return (
    <MeshComp castShadow receiveShadow>
      {modelType === 'box' && <boxGeometry args={[1, 1, 1]} />}
      {modelType === 'sphere' && <sphereGeometry args={[0.7, 64, 64]} />}
      {modelType === 'torus' && <torusGeometry args={[0.5, 0.2, 32, 100]} />}
      {modelType === 'cylinder' && <cylinderGeometry args={[0.5, 0.5, 1, 32]} />}
      {modelType === 'cone' && <coneGeometry args={[0.5, 1, 32]} />}
      {modelType === 'knot' && <torusKnotGeometry args={[0.4, 0.15, 128, 32]} />}
      {modelType === 'icosahedron' && <icosahedronGeometry args={[0.8, 15]} />}

      {activeSettings ? (
        <Primitive object={createMaterial(activeSettings)} attach="material" />
      ) : (
        <MeshStandardMaterial color="#3b82f6" />
      )}
    </MeshComp>
  );
};

export default SceneModel;

