          <strong className="text-blue-400 uppercase tracking-tight">Pro Tip:</strong> This code preserves the <code className="text-slate-300 bg-slate-800 px-1 rounded">.name</code> mapping logic. Ensure your GLTF meshes have unique material names for the override to work correctly.
        </p>
      </div>
    </div>
  );
};

