export type TabType = 'settings' | 'lights' | 'code';

import React, { useState, useCallback, useRef, Suspense, useTransition } from 'react';
import { Canvas } from '@react-three/fiber';
import * as THREE from 'three';
import { 
  OrbitControls, 
  PerspectiveCamera, 
  Grid, 
  Environment,
  ContactShadows,
  Float,
  BakeShadows
} from '@react-three/drei';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import { Settings2, Code, Upload, Loader2, Package, Sun, Lightbulb } from 'lucide-react';
import { INITIAL_STATE, createDefaultMaterial } from './constants';
import { AppState, TabType, LightSettings } from './types';

// Sub-components
import Sidebar from './components/Sidebar';
import CodePanel from './components/CodePanel';
import SceneModel from './components/SceneModel';
import LightsPanel from './components/LightsPanel';

const AmbientLight = 'ambientLight' as any;
const DirectionalLight = 'directionalLight' as any;
const PointLight = 'pointLight' as any;
const SpotLight = 'spotLight' as any;
const OrthographicCamera = 'orthographicCamera' as any;
const Group = 'group' as any;
const MeshComp = 'mesh' as any;
const PlaneGeometry = 'planeGeometry' as any;
const MeshStandardMaterial = 'meshStandardMaterial' as any;
const Color = 'color' as any;

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');
  const [customModel, setCustomModel] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const updateState = useCallback(<K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => {
    const update = () => {
      setState(prev => ({
        ...prev,
        [category]: category === 'materials' 
          ? { ...prev.materials, [state.selectedMaterialId]: { ...prev.materials[state.selectedMaterialId], [key]: value } }
          : { ...prev[category], [key]: value }
      }));
    };

    if (key === 'type' || key === 'modelType') {
      startTransition(update);
    } else {
      update();
    }
  }, [state.selectedMaterialId]);

  const setTopState = useCallback(<K extends keyof AppState>(key: K, value: AppState[K]) => {
    setState(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);

      startTransition(() => {
        setCustomModel(url);
        setState(prev => ({
          ...prev,
          scene: { ...prev.scene, modelType: 'custom' }
        }));
      });
    }
  };

  const onMaterialsDiscovered = useCallback((discoveredMaterials: string[]) => {
    setState(prev => {
      const newMaterials = { ...prev.materials };
      let firstId = prev.selectedMaterialId;

      discoveredMaterials.forEach((name, index) => {
        const id = `mat-${name || index}`;
        if (!newMaterials[id]) {
          newMaterials[id] = createDefaultMaterial(id, name || `Material ${index + 1}`);
        }
        if (index === 0 && (prev.selectedMaterialId === 'default-material' || !prev.materials[prev.selectedMaterialId])) {
          firstId = id;
        }
      });

      return {
        ...prev,
        materials: newMaterials,
        selectedMaterialId: firstId
      };
    });
  }, []);

  const handleUpdateLights = (lights: LightSettings[]) => {
    setState(prev => ({ ...prev, lights }));
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        className="hidden" 
        accept=".glb,.gltf,.obj"
      />

      <main className="relative flex-1 bg-black">
        {isPending && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-50 pointer-events-none">
            <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
          </div>
        )}

        <Canvas 
          shadows={{ type: THREE.PCFSoftShadowMap }} 
          dpr={[1, 2]} 
          gl={{ antialias: true, alpha: false, stencil: false }}
        >
          <Color attach="background" args={[state.scene.background]} />

          <PerspectiveCamera makeDefault position={[4, 3, 4]} fov={50} />
          <OrbitControls 
            makeDefault 
            autoRotate={state.scene.autoRotate} 
            autoRotateSpeed={0.5} 
            enableDamping 
          />

          <AmbientLight intensity={state.scene.ambientIntensity} />

          {state.lights.map((light) => {
            if (light.type === 'directional') {
              return (
                <DirectionalLight 
                  key={light.id}
                  position={light.position} 
                  intensity={light.intensity} 
                  color={light.color}
                  castShadow={light.castShadow}
                  shadow-mapSize={[1024, 1024]}
                >
                  <OrthographicCamera attach="shadow-camera" args={[-10, 10, 10, -10, 0.5, 30]} />
                </DirectionalLight>
              );
            }
            if (light.type === 'point') {
              return (
                <PointLight 
                  key={light.id}
                  position={light.position}
                  intensity={light.intensity}
                  color={light.color}
                  castShadow={light.castShadow}
                />
              );
            }
            if (light.type === 'spot') {
              return (
                <SpotLight 
                  key={light.id}
                  position={light.position}
                  intensity={light.intensity}
                  color={light.color}
                  castShadow={light.castShadow}
                />
              );
            }
            if (light.type === 'ambient') {
              return <AmbientLight key={light.id} intensity={light.intensity} color={light.color} />;
            }
            return null;
          })}

          <Environment preset="city" />

          <Group position={[0, 0, 0]}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <Suspense fallback={null}>
                <SceneModel 
                  materials={state.materials} 
                  modelType={state.scene.modelType} 
                  customUrl={customModel} 
                  override={state.scene.overrideMaterials}
                  onMaterialsFound={onMaterialsDiscovered}
                />
              </Suspense>
            </Float>
          </Group>

          {state.scene.showPlane && (
            <MeshComp rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.0, 0]} receiveShadow>
              <PlaneGeometry args={[100, 100]} />
              <MeshStandardMaterial 
                color={state.scene.planeColor} 
                roughness={state.scene.planeRoughness} 
                metalness={0.1} 
                transparent={state.scene.planeOpacity < 1}
                opacity={state.scene.planeOpacity}
              />
            </MeshComp>
          )}

          {state.scene.contactShadows && (
            <ContactShadows 
              position={[0, -0.99, 0]} 
              opacity={state.scene.shadowOpacity} 
              scale={15} 
              blur={state.scene.shadowBlur} 
              far={3} 
            />
          )}

          {state.scene.gridHelper && state.scene.showPlane && (
            <Grid 
              position={[0, -0.995, 0]} 
              args={[20, 20]} 
              sectionColor="#cbd5e1" 
              cellColor="#94a3b8" 
              fadeDistance={25} 
              infiniteGrid
            />
          )}

          <EffectComposer multisampling={4}>
            {state.bloom.enabled && (
              <Bloom 
                luminanceThreshold={state.bloom.threshold} 
                mipmapBlur 
                intensity={state.bloom.intensity} 
                radius={state.bloom.radius} 
              />
            )}
          </EffectComposer>
          <BakeShadows />
        </Canvas>

        <div className="absolute top-6 left-6 pointer-events-none select-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400">
            Three.js Visualizer
          </h1>
          <p className="text-slate-500 text-[10px] tracking-[0.3em] uppercase mt-1 flex items-center gap-2">
            <Package size={10} />
            {state.scene.modelType === 'custom' ? 'Complex Multi-Mesh Asset' : 'Internal Geometry'}
          </p>
        </div>

        <button 
          onClick={() => fileInputRef.current?.click()}
          className="absolute bottom-6 left-6 p-4 bg-blue-600 hover:bg-blue-500 rounded-full shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all hover:scale-110 active:scale-95 group"
          title="Upload GLB/OBJ"
        >
          <Upload size={24} className="text-white" />
        </button>
      </main>

      <div className="w-[440px] h-full bg-slate-900/98 backdrop-blur-xl border-l border-slate-800 flex flex-col shadow-2xl z-10 overflow-hidden">
        <div className="flex border-b border-slate-800">
          <button onClick={() => setActiveTab('settings')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 ${activeTab === 'settings' ? 'text-blue-400 border-blue-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}>
            <Settings2 size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Props</span>
          </button>
          <button onClick={() => setActiveTab('lights')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 ${activeTab === 'lights' ? 'text-amber-400 border-amber-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}>
            <Lightbulb size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Lights</span>
          </button>
          <button onClick={() => setActiveTab('code')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 ${activeTab === 'code' ? 'text-emerald-400 border-emerald-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}>
            <Code size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Code</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' && (
            <Sidebar 
              state={state} 
              updateState={updateState} 
              setSelectedMaterialId={(id) => setTopState('selectedMaterialId', id)}
            />
          )}
          {activeTab === 'lights' && (
            <LightsPanel 
              lights={state.lights} 
              onUpdateLights={handleUpdateLights} 
            />
          )}
          {activeTab === 'code' && (
            <CodePanel state={state} />
          )}
        </div>
      </div>
    </div>
  );
}

