import React, { useState } from 'react';
import { AppState, MaterialSettings, LightSettings } from '../types';
import { Copy, Check, Terminal, Cpu } from 'lucide-react';

interface CodePanelProps {
  state: AppState;
}

const CodePanel: React.FC<CodePanelProps> = ({ state }) => {
  const [copied, setCopied] = useState(false);

  const getMaterialType = (mat: MaterialSettings) => {
    switch (mat.type) {
      case 'basic': return 'MeshBasicMaterial';
      case 'lambert': return 'MeshLambertMaterial';
      case 'phong': return 'MeshPhongMaterial';
      case 'toon': return 'MeshToonMaterial';
      case 'normal': return 'MeshNormalMaterial';
      case 'depth': return 'MeshDepthMaterial';
      case 'physical': return 'MeshPhysicalMaterial';
      case 'matcap': return 'MeshMatcapMaterial';
      default: return 'MeshStandardMaterial';
    }
  };

  const generateMaterialProps = (mat: MaterialSettings) => {
    const props: string[] = [];
    if (mat.type !== 'normal' && mat.type !== 'depth') {
      props.push(`    color: '${mat.color}'`);
    }
    props.push(`    transparent: ${mat.opacity < 1 || mat.transmission > 0}`);
    props.push(`    opacity: ${mat.opacity.toFixed(2)}`);
    props.push(`    wireframe: ${mat.wireframe}`);
    props.push(`    name: '${mat.name}'`);

    if (['phong', 'lambert', 'standard', 'physical'].includes(mat.type)) {
      props.push(`    emissive: '${mat.emissive}'`);
      props.push(`    emissiveIntensity: ${mat.emissiveIntensity.toFixed(1)}`);
    }

    if (mat.type === 'phong') {
      props.push(`    specular: '${mat.specular}'`);
      props.push(`    shininess: ${mat.shininess.toFixed(0)}`);
    }

    if (['standard', 'physical'].includes(mat.type)) {
      props.push(`    metalness: ${mat.metalness.toFixed(2)}`);
      props.push(`    roughness: ${mat.roughness.toFixed(2)}`);
      props.push(`    envMapIntensity: ${mat.envMapIntensity.toFixed(1)}`);
    }

    if (mat.type === 'physical') {
      props.push(`    clearcoat: ${mat.clearcoat.toFixed(2)}`);
      props.push(`    clearcoatRoughness: ${mat.clearcoatRoughness.toFixed(2)}`);
      props.push(`    transmission: ${mat.transmission.toFixed(2)}`);
      props.push(`    thickness: ${mat.thickness.toFixed(2)}`);
      props.push(`    ior: ${mat.ior.toFixed(2)}`);
    }

    return props.join(',\n');
  };

  const materialsCode = (Object.values(state.materials) as MaterialSettings[])
    .map(mat => `  '${mat.name}': new THREE.${getMaterialType(mat)}({
${generateMaterialProps(mat)}
  })`)
    .join(',\n');

  const generateLightCode = (light: LightSettings) => {
    const tag = light.type === 'ambient' ? 'ambientLight' : 
                light.type === 'directional' ? 'directionalLight' :
                light.type === 'point' ? 'pointLight' : 
                light.type === 'hemisphere' ? 'hemisphereLight' :
                light.type === 'rectArea' ? 'rectAreaLight' : 'spotLight';

    let extra = '';
    if (light.type === 'hemisphere') {
      extra = `\n        args={['${light.color}', '${light.groundColor}', ${light.intensity}]}` +
              `\n        position={[${light.position.join(', ')}]}`;
    } else if (light.type === 'rectArea') {
      extra = `\n        color="${light.color}"` +
              `\n        intensity={${light.intensity.toFixed(1)}}` +
              `\n        width={${light.width}}` +
              `\n        height={${light.height}}` +
              `\n        position={[${light.position.join(', ')}]}` +
              `\n        rotation={[${light.rotation?.join(', ')}]}`;
    } else if (light.type !== 'ambient') {
      extra = `\n        color="${light.color}"` +
              `\n        intensity={${light.intensity.toFixed(1)}}` +
              `\n        position={[${light.position.join(', ')}]}` +
              `\n        castShadow={${light.castShadow}}`;
    } else {
       extra = `\n        color="${light.color}"` +
               `\n        intensity={${light.intensity.toFixed(1)}}`;
    }

    return `      <${tag}${extra} />`;
  };

  const lightsCode = state.lights.map(generateLightCode).join('\n');

  const fullComponentCode = `import React, { useMemo, useEffect } from 'react'
import { Canvas } from '@react-three/fiber'
import { useGLTF, Environment, ContactShadows, OrbitControls } from '@react-three/drei'
import { EffectComposer, Bloom } from '@react-three/postprocessing'
import * as THREE from 'three'

/**
 * Three.js Visualizer - Custom Model Component
 */
function Model({ materialsConfig, overrideEnabled }) {
  const { scene } = useGLTF('${state.scene.modelType === 'custom' ? 'your-model-url.glb' : state.scene.modelType}')

  const materials = useMemo(() => ({
${materialsCode}
  }), [])

  useEffect(() => {
    scene.traverse((child) => {
      if (child.isMesh) {
        child.castShadow = true
        child.receiveShadow = true

        if (overrideEnabled) {
          if (Array.isArray(child.material)) {
            child.material = child.material.map(m => materials[m.name] || m)
          } else if (child.material) {
            const matched = materials[child.material.name]
            if (matched) child.material = matched
          }
        }
      }
    })
  }, [scene, materials, overrideEnabled])

  return <primitive object={scene} />
}

export default function Scene() {
  return (
    <Canvas shadows camera={{ position: [4, 3, 4], fov: 50 }}>
      <color attach="background" args={['${state.scene.background}']} />
      <OrbitControls makeDefault />

      {/* Lighting Configuration */}
${lightsCode}

      <React.Suspense fallback={null}>
        <Model overrideEnabled={${state.scene.overrideMaterials}} />
        <Environment preset="city" />
      </React.Suspense>

      {/* Post Processing */}
      <EffectComposer>
        <Bloom 
          intensity={${state.bloom.intensity.toFixed(1)}} 
          luminanceThreshold={${state.bloom.threshold.toFixed(2)}} 
          mipmapBlur 
        />
      </EffectComposer>

      {/* Floor Elements */}
${state.scene.showPlane ? `      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -1, 0]} receiveShadow>
        <planeGeometry args={[100, 100]} />
        <meshStandardMaterial color="${state.scene.planeColor}" roughness={${state.scene.planeRoughness}} />
      </mesh>` : ''}
${state.scene.contactShadows ? `      <ContactShadows position={[0, -0.99, 0]} opacity={${state.scene.shadowOpacity}} scale={10} blur={${state.scene.shadowBlur}} />` : ''}
    </Canvas>
  )
}`;

  const handleCopy = () => {
    navigator.clipboard.writeText(fullComponentCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in slide-in-from-right-4 duration-500 pb-10">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-2">
          <div className="p-1.5 bg-emerald-500/10 rounded-lg">
            <Cpu size={14} className="text-emerald-400" />
          </div>
          <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Three.js Visualizer Code</span>
        </div>
        <button 
          onClick={handleCopy}
          className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 rounded-lg transition-all text-slate-400 hover:text-white border border-slate-700 cursor-pointer"
        >
          {copied ? <Check size={12} className="text-emerald-400" /> : <Terminal size={12} />}
          <span className="text-[10px] font-bold uppercase">{copied ? 'Copied' : 'Copy All'}</span>
        </button>
      </div>

      <div className="flex-1 bg-black/50 rounded-xl border border-slate-800 p-6 overflow-auto fira-code text-[11px] leading-relaxed relative">
        <pre className="text-blue-300/90 whitespace-pre">
          {fullComponentCode.split('\n').map((line, i) => {
            const isComment = line.trim().startsWith('//') || line.trim().startsWith('/*') || line.trim().startsWith('*');
            const isImport = line.trim().startsWith('import');
            return (
              <div key={i} className={`${isComment ? 'text-slate-600 italic' : isImport ? 'text-purple-400' : ''} min-h-[1.2em]`}>
                {line}
              </div>
            );
          })}
        </pre>
      </div>
    </div>
  );
};

export default CodePanel;

import React, { useState, useCallback, useRef, Suspense, useTransition } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { 
  OrbitControls, 
  PerspectiveCamera, 
  Grid, 
  Environment,
  ContactShadows,
  Float,
  BakeShadows,
  useHelper
} from '@react-three/drei';
import { RectAreaLight as ThreeRectAreaLight } from 'three';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import { Settings2, Code, Upload, Loader2, Package, Lightbulb } from 'lucide-react';
import { INITIAL_STATE, createDefaultMaterial } from './constants';
import { AppState, TabType, LightSettings, MaterialSettings } from './types';

// Sub-components
import Sidebar from './components/Sidebar';
import CodePanel from './components/CodePanel';
import SceneModel from './components/SceneModel';
import LightsPanel from './components/LightsPanel';

const AmbientLightComp = 'ambientLight' as any;
const DirectionalLightComp = 'directionalLight' as any;
const PointLightComp = 'pointLight' as any;
const SpotLightComp = 'spotLight' as any;
const HemisphereLightComp = 'hemisphereLight' as any;
const RectAreaLightComp = 'rectAreaLight' as any;
const OrthographicCameraComp = 'orthographicCamera' as any;
const GroupComp = 'group' as any;
const MeshComp = 'mesh' as any;
const PlaneGeometryComp = 'planeGeometry' as any;
const MeshStandardMaterialComp = 'meshStandardMaterial' as any;
const ColorComp = 'color' as any;

/**
 * Individual Light Component with Optional Helper
 */
// Fixed: Explicitly typed as React.FC to include standard props like 'key' and resolve assignability issues in lists.
const DynamicLight: React.FC<{ light: LightSettings, showHelper: boolean }> = ({ light, showHelper }) => {
  const lightRef = useRef<any>(null);

  // Use appropriate helpers based on type
  useHelper(showHelper && light.type === 'directional' ? lightRef : null, THREE.DirectionalLightHelper, 1, 'white');
  useHelper(showHelper && light.type === 'point' ? lightRef : null, THREE.PointLightHelper, 0.5, light.color);
  useHelper(showHelper && light.type === 'spot' ? lightRef : null, THREE.SpotLightHelper, 'white');
  useHelper(showHelper && light.type === 'hemisphere' ? lightRef : null, THREE.HemisphereLightHelper, 2, light.color);

  switch (light.type) {
    case 'directional':
      return (
        <DirectionalLightComp 
          ref={lightRef}
          position={light.position} 
          intensity={light.intensity} 
          color={light.color}
          castShadow={light.castShadow}
          shadow-mapSize={[1024, 1024]}
        >
          <OrthographicCameraComp attach="shadow-camera" args={[-10, 10, 10, -10, 0.5, 30]} />
        </DirectionalLightComp>
      );
    case 'point':
      return (
        <PointLightComp 
          ref={lightRef}
          position={light.position}
          intensity={light.intensity}
          color={light.color}
          castShadow={light.castShadow}
        />
      );
    case 'spot':
      return (
        <SpotLightComp 
          ref={lightRef}
          position={light.position}
          intensity={light.intensity}
          color={light.color}
          castShadow={light.castShadow}
          angle={0.3}
          penumbra={1}
        />
      );
    case 'hemisphere':
      return (
        <HemisphereLightComp
          ref={lightRef}
          position={light.position}
          args={[light.color, light.groundColor, light.intensity]}
        />
      );
    case 'rectArea':
      return (
        <RectAreaLightComp
          ref={lightRef}
          position={light.position}
          rotation={light.rotation || [0, 0, 0]}
          intensity={light.intensity}
          width={light.width || 4}
          height={light.height || 4}
          color={light.color}
        />
      );
    case 'ambient':
      return <AmbientLightComp intensity={light.intensity} color={light.color} />;
    default:
      return null;
  }
};

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');
  const [customModel, setCustomModel] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const updateState = useCallback(<K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => {
    setState(prev => ({
      ...prev,
      [category]: { ...prev[category], [key]: value }
    }));
  }, []);

  const updateMaterial = useCallback(<S extends keyof MaterialSettings>(
    key: S,
    value: MaterialSettings[S]
  ) => {
    setState(prev => {
      const currentId = prev.selectedMaterialId;
      if (!prev.materials[currentId]) return prev;
      return {
        ...prev,
        materials: {
          ...prev.materials,
          [currentId]: { ...prev.materials[currentId], [key]: value }
        }
      };
    });
  }, []);

  const setTopState = useCallback(<K extends keyof AppState>(key: K, value: AppState[K]) => {
    setState(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);

      startTransition(() => {
        setCustomModel(url);
        setState(prev => ({
          ...prev,
          scene: { ...prev.scene, modelType: 'custom' }
        }));
      });
    }
  };

  const onMaterialsDiscovered = useCallback((discoveredMaterials: string[]) => {
    setState(prev => {
      const newMaterials = { ...prev.materials };
      let firstId = prev.selectedMaterialId;

      discoveredMaterials.forEach((name, index) => {
        const id = `mat-${name || index}`;
        if (!newMaterials[id]) {
          newMaterials[id] = createDefaultMaterial(id, name || `Material ${index + 1}`);
        }
        if (index === 0 && (prev.selectedMaterialId === 'default-material' || !prev.materials[prev.selectedMaterialId])) {
          firstId = id;
        }
      });

      return {
        ...prev,
        materials: newMaterials,
        selectedMaterialId: firstId
      };
    });
  }, []);

  const handleUpdateLights = (lights: LightSettings[]) => {
    setState(prev => ({ ...prev, lights }));
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        className="hidden" 
        accept=".glb,.gltf,.obj"
      />

      <main className="relative flex-1 bg-black">
        {isPending && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-50 pointer-events-none">
            <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
          </div>
        )}

        <Canvas 
          shadows={{ type: THREE.PCFSoftShadowMap }} 
          dpr={[1, 2]} 
          gl={{ antialias: true, alpha: false, stencil: false }}
        >
          <ColorComp attach="background" args={[state.scene.background]} />

          <PerspectiveCamera makeDefault position={[4, 3, 4]} fov={50} />
          <OrbitControls 
            makeDefault 
            autoRotate={state.scene.autoRotate} 
            autoRotateSpeed={0.5} 
            enableDamping 
          />

          <AmbientLightComp intensity={state.scene.ambientIntensity} />

          {state.lights.map((light) => (
            <DynamicLight 
              key={light.id} 
              light={light} 
              showHelper={state.scene.showHelpers} 
            />
          ))}

          <Environment preset="city" />

          <GroupComp position={[0, 0, 0]}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <Suspense fallback={null}>
                <SceneModel 
                  materials={state.materials} 
                  modelType={state.scene.modelType} 
                  customUrl={customModel} 
                  override={state.scene.overrideMaterials}
                  onMaterialsFound={onMaterialsDiscovered}
                />
              </Suspense>
            </Float>
          </GroupComp>

          {state.scene.showPlane && (
            <MeshComp rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.0, 0]} receiveShadow>
              <PlaneGeometryComp args={[100, 100]} />
              <MeshStandardMaterialComp 
                color={state.scene.planeColor} 
                roughness={state.scene.planeRoughness} 
                metalness={0.1} 
                transparent={state.scene.planeOpacity < 1}
                opacity={state.scene.planeOpacity}
              />
            </MeshComp>
          )}

          {state.scene.contactShadows && (
            <ContactShadows 
              position={[0, -0.99, 0]} 
              opacity={state.scene.shadowOpacity} 
              scale={15} 
              blur={state.scene.shadowBlur} 
              far={3} 
            />
          )}

          {state.scene.gridHelper && state.scene.showPlane && (
            <Grid 
              position={[0, -0.995, 0]} 
              args={[20, 20]} 
              sectionColor="#cbd5e1" 
              cellColor="#94a3b8" 
              fadeDistance={25} 
              infiniteGrid
            />
          )}

          <EffectComposer multisampling={4}>
            {state.bloom.enabled && (
              <Bloom 
                luminanceThreshold={state.bloom.threshold} 
                mipmapBlur 
                intensity={state.bloom.intensity} 
                radius={state.bloom.radius} 
              />
            )}
          </EffectComposer>
          <BakeShadows />
        </Canvas>

        <div className="absolute top-6 left-6 pointer-events-none select-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400">
            Three.js Visualizer
          </h1>
          <p className="text-slate-500 text-[10px] tracking-[0.3em] uppercase mt-1 flex items-center gap-2">
            <Package size={10} />
            {state.scene.modelType === 'custom' ? 'Complex Multi-Mesh Asset' : 'Internal Geometry'}
          </p>
        </div>

        <button 
          onClick={() => fileInputRef.current?.click()}
          className="absolute bottom-6 left-6 p-4 bg-blue-600 hover:bg-blue-500 rounded-full shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all hover:scale-110 active:scale-95 group"
          title="Upload GLB/OBJ"
        >
          <Upload size={24} className="text-white" />
        </button>
      </main>

      <div className="w-[440px] h-full bg-slate-900/98 backdrop-blur-xl border-l border-slate-800 flex flex-col shadow-2xl z-10 overflow-hidden">
        <div className="flex border-b border-slate-800">
          <button 
            onClick={() => setActiveTab('settings')} 
            className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'settings' ? 'text-blue-400 border-blue-500 bg-slate-800/30' : 'text-slate-50 border-transparent hover:text-slate-300'}`}
          >
            <Settings2 size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Props</span>
          </button>
          <button 
            onClick={() => setActiveTab('lights')} 
            className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'lights' ? 'text-amber-400 border-amber-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
          >
            <Lightbulb size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Lights</span>
          </button>
          <button 
            onClick={() => setActiveTab('code')} 
            className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'code' ? 'text-emerald-400 border-emerald-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
          >
            <Code size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Code</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' && (
            <Sidebar 
              state={state} 
              updateState={updateState} 
              updateMaterial={updateMaterial}
              setSelectedMaterialId={(id) => setTopState('selectedMaterialId', id)}
            />
          )}
          {activeTab === 'lights' && (
            <LightsPanel 
              lights={state.lights} 
              onUpdateLights={handleUpdateLights} 
              showHelpers={state.scene.showHelpers}
              onToggleHelpers={(v) => updateState('scene', 'showHelpers', v)}
            />
          )}
          {activeTab === 'code' && (
            <CodePanel state={state} />
          )}
        </div>
      </div>
    </div>
  );
}

export type MaterialType = 'basic' | 'phong' | 'standard' | 'physical' | 'lambert' | 'toon' | 'normal' | 'depth' | 'matcap';
