}

export interface MaterialSettings {
  id: string;
  name: string;
  type: MaterialType;
  color: string;
  emissive: string;
  emissiveIntensity: number;
  metalness: number;
  roughness: number;
  wireframe: boolean;
  opacity: number;
  transparent: boolean;
  envMapIntensity: number;
  clearcoat: number;
  clearcoatRoughness: number;
  transmission: number;
  thickness: number;
  ior: number;
  specularIntensity: number;
  shininess: number;
  specular: string;
  depthPacking: boolean;
  matcapUrl?: string;
}

