const SpotLightComp = 'spotLight' as any;
const HemisphereLightComp = 'hemisphereLight' as any;
const RectAreaLightComp = 'rectAreaLight' as any;
const LightProbeComp = 'lightProbe' as any;
const OrthographicCameraComp = 'orthographicCamera' as any;
const GroupComp = 'group' as any;
const MeshComp = 'mesh' as any;
const PlaneGeometryComp = 'planeGeometry' as any;
const MeshStandardMaterialComp = 'meshStandardMaterial' as any;
const ColorComp = 'color' as any;

/**
 * Individual Light Component with Optional Helper
 */
const DynamicLight: React.FC<{ light: LightSettings, showHelper: boolean }> = ({ light, showHelper }) => {
  const lightRef = useRef<any>(null);

  // Core Helpers
  useHelper(showHelper && light.type === 'directional' ? lightRef : null, THREE.DirectionalLightHelper, 1, 'white');
  useHelper(showHelper && light.type === 'point' ? lightRef : null, THREE.PointLightHelper, 0.5, light.color);
  useHelper(showHelper && light.type === 'spot' ? lightRef : null, THREE.SpotLightHelper, 'white');
  useHelper(showHelper && light.type === 'hemisphere' ? lightRef : null, THREE.HemisphereLightHelper, 2, light.color);

  switch (light.type) {
    case 'directional':
      return (
        <DirectionalLightComp 
          ref={lightRef}
          position={light.position} 
          intensity={light.intensity} 
          color={light.color}
          castShadow={light.castShadow}
        >
          <OrthographicCameraComp attach="shadow-camera" args={[-10, 10, 10, -10, 0.5, 30]} />
        </DirectionalLightComp>
      );
    case 'point':
      return (
        <PointLightComp 
          ref={lightRef}
          position={light.position}
          intensity={light.intensity}
          color={light.color}
          castShadow={light.castShadow}
        />
      );
    case 'spot':
      return (
        <SpotLightComp 
          ref={lightRef}
          position={light.position}
          intensity={light.intensity}
          color={light.color}
          castShadow={light.castShadow}
          angle={0.3}
          penumbra={1}
        />
      );
    case 'hemisphere':
      return (
        <HemisphereLightComp
          ref={lightRef}
          position={light.position}
          args={[light.color, light.groundColor, light.intensity]}
        />
      );
    case 'rectArea':
      return (
        <RectAreaLightComp
          ref={lightRef}
          position={light.position}
          rotation={light.rotation || [0, 0, 0]}
          intensity={light.intensity}
          width={light.width || 4}
          height={light.height || 4}
          color={light.color}
        />
      );
    case 'ambient':
      return <AmbientLightComp intensity={light.intensity} color={light.color} />;
    case 'lightProbe':
      return <LightProbeComp ref={lightRef} intensity={light.intensity} />;
    default:
      return null;
  }
};

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');
  const [customModel, setCustomModel] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const updateState = useCallback(<K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => {
    setState(prev => ({
      ...prev,
      [category]: { ...prev[category], [key]: value }
    }));
  }, []);

  const updateMaterial = useCallback(<S extends keyof MaterialSettings>(
    key: S,
    value: MaterialSettings[S]
  ) => {
    setState(prev => {
      const currentId = prev.selectedMaterialId;
      if (!prev.materials[currentId]) return prev;
      return {
        ...prev,
        materials: {
          ...prev.materials,
          [currentId]: { ...prev.materials[currentId], [key]: value }
        }
      };
    });
  }, []);

  const setTopState = useCallback(<K extends keyof AppState>(key: K, value: AppState[K]) => {
    setState(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);

      startTransition(() => {
        setCustomModel(url);
        setState(prev => ({
          ...prev,
          scene: { ...prev.scene, modelType: 'custom' }
        }));
      });
    }
  };

  const onMaterialsDiscovered = useCallback((discoveredMaterials: string[]) => {
    setState(prev => {
      const newMaterials = { ...prev.materials };
      let firstId = prev.selectedMaterialId;

      discoveredMaterials.forEach((name, index) => {
        const id = `mat-${name || index}`;
        if (!newMaterials[id]) {
          newMaterials[id] = createDefaultMaterial(id, name || `Material ${index + 1}`);
        }
        if (index === 0 && (prev.selectedMaterialId === 'default-material' || !prev.materials[prev.selectedMaterialId])) {
          firstId = id;
        }
      });

      return {
        ...prev,
        materials: newMaterials,
        selectedMaterialId: firstId
      };
    });
  }, []);

  const handleUpdateLights = (lights: LightSettings[]) => {
    setState(prev => ({ ...prev, lights }));
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        className="hidden" 
        accept=".glb,.gltf,.obj"
      />

      <main className="relative flex-1 bg-black">
        {isPending && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-50 pointer-events-none">
            <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
          </div>
        )}

        <Canvas 
          shadows={{ type: THREE.PCFSoftShadowMap }} 
          dpr={[1, 2]} 
          gl={{ antialias: true, alpha: false, stencil: false }}
        >
          <ColorComp attach="background" args={[state.scene.background]} />

          <PerspectiveCamera makeDefault position={[4, 3, 4]} fov={50} />
          <OrbitControls 
            makeDefault 
            autoRotate={state.scene.autoRotate} 
            autoRotateSpeed={0.5} 
            enableDamping 
          />

          <AmbientLightComp intensity={state.scene.ambientIntensity} />

          {state.lights.map((light) => (
            <DynamicLight 
              key={light.id} 
              light={light} 
              showHelper={state.scene.showHelpers} 
            />
          ))}

          {state.scene.environmentPreset !== 'none' && (
            <Environment preset={state.scene.environmentPreset as any} />
          )}

          <GroupComp position={[0, 0, 0]}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <Suspense fallback={null}>
                <SceneModel 
                  materials={state.materials} 
                  modelType={state.scene.modelType} 
                  customUrl={customModel} 
                  override={state.scene.overrideMaterials}
                  onMaterialsFound={onMaterialsDiscovered}
                />
              </Suspense>
            </Float>
          </GroupComp>

          {state.scene.showPlane && (
            <MeshComp rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.0, 0]} receiveShadow>
              <PlaneGeometryComp args={[100, 100]} />
              <MeshStandardMaterialComp 
                color={state.scene.planeColor} 
                roughness={state.scene.planeRoughness} 
                metalness={0.1} 
                transparent={state.scene.planeOpacity < 1}
                opacity={state.scene.planeOpacity}
              />
            </MeshComp>
          )}

          {state.scene.contactShadows && (
            <ContactShadows 
              position={[0, -0.99, 0]} 
              opacity={state.scene.shadowOpacity} 
              scale={15} 
              blur={state.scene.shadowBlur} 
              far={3} 
            />
          )}

          {state.scene.gridHelper && state.scene.showPlane && (
            <Grid 
              position={[0, -0.995, 0]} 
              args={[20, 20]} 
              sectionColor="#cbd5e1" 
              cellColor="#94a3b8" 
              fadeDistance={25} 
              infiniteGrid
            />
          )}

          <EffectComposer multisampling={4}>
            {state.bloom.enabled && (
              <Bloom 
                luminanceThreshold={state.bloom.threshold} 
                mipmapBlur 
                intensity={state.bloom.intensity} 
                radius={state.bloom.radius} 
              />
            )}
          </EffectComposer>
          <BakeShadows />
        </Canvas>

        <div className="absolute top-6 left-6 pointer-events-none select-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400">
            Three.js Visualizer
          </h1>
          <p className="text-slate-500 text-[10px] tracking-[0.3em] uppercase mt-1 flex items-center gap-2">
            <Package size={10} />
            {state.scene.modelType === 'custom' ? 'Complex Multi-Mesh Asset' : 'Internal Geometry'}
          </p>
        </div>

        <button 
          onClick={() => fileInputRef.current?.click()}
          className="absolute bottom-6 left-6 p-4 bg-blue-600 hover:bg-blue-500 rounded-full shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all hover:scale-110 active:scale-95 group cursor-pointer"
          title="Upload GLB/OBJ"
        >
          <Upload size={24} className="text-white" />
        </button>
      </main>

      <div className="w-[440px] h-full bg-slate-900/98 backdrop-blur-xl border-l border-slate-800 flex flex-col shadow-2xl z-10 overflow-hidden">
        <div className="flex border-b border-slate-800">
          <button 
            onClick={() => setActiveTab('settings')} 
            className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'settings' ? 'text-blue-400 border-blue-500 bg-slate-800/30' : 'text-slate-50 border-transparent hover:text-slate-300'}`}
          >
            <Settings2 size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Props</span>
          </button>
          <button 
            onClick={() => setActiveTab('lights')} 
            className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'lights' ? 'text-amber-400 border-amber-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
          >
            <Lightbulb size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Lights</span>
          </button>
          <button 
            onClick={() => setActiveTab('code')} 
            className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'code' ? 'text-emerald-400 border-emerald-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
          >
            <Code size={16} /> <span className="text-[11px] font-bold uppercase tracking-widest">Code</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' && (
            <Sidebar 
              state={state} 
              updateState={updateState} 
              updateMaterial={updateMaterial}
              setSelectedMaterialId={(id) => setTopState('selectedMaterialId', id)}
            />
          )}
          {activeTab === 'lights' && (
            <LightsPanel 
              lights={state.lights} 
              onUpdateLights={handleUpdateLights} 
              showHelpers={state.scene.showHelpers}
              onToggleHelpers={(v) => updateState('scene', 'showHelpers', v)}
              sceneAmbient={state.scene.ambientIntensity}
              onUpdateSceneAmbient={(v) => updateState('scene', 'ambientIntensity', v)}
              envPreset={state.scene.environmentPreset}
              onUpdateEnvPreset={(v) => updateState('scene', 'environmentPreset', v)}
            />
          )}
          {activeTab === 'code' && (
            <CodePanel state={state} />
          )}
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { LightSettings, LightType } from '../types';
import { Lightbulb, Trash2, Plus, Eye, EyeOff, Globe, Sun } from 'lucide-react';

interface LightsPanelProps {
  lights: LightSettings[];
  onUpdateLights: (lights: LightSettings[]) => void;
  showHelpers: boolean;
  onToggleHelpers: (v: boolean) => void;
  sceneAmbient: number;
  onUpdateSceneAmbient: (v: number) => void;
  envPreset: string;
  onUpdateEnvPreset: (v: string) => void;
}

const ControlGroup: React.FC<React.PropsWithChildren<{ title: string, icon: any, onRemove?: () => void }>> = ({ title, icon: Icon, children, onRemove }) => (
  <div className="mb-8 p-4 bg-slate-800/20 rounded-xl border border-slate-800/50">
    <div className="flex items-center justify-between mb-5">
      <div className="flex items-center gap-2 text-slate-300">
        <div className="p-1.5 bg-slate-800 rounded-lg">
          <Icon size={14} className="text-amber-400" />
        </div>
        <h3 className="text-[10px] font-black uppercase tracking-[0.2em]">{title}</h3>
      </div>
      {onRemove && (
        <button onClick={onRemove} className="text-slate-600 hover:text-red-400 transition-colors cursor-pointer">
          <Trash2 size={14} />
        </button>
      )}
    </div>
    <div className="space-y-6">
      {children}
    </div>
  </div>
);

const Slider = ({ label, value, min, max, step, onChange, unit = "" }: any) => (
  <div className="group">
    <div className="flex justify-between items-center mb-1.5">
      <label className="text-[11px] font-medium text-slate-400 group-hover:text-slate-200 transition-colors">{label}</label>
      <span className="text-[10px] font-mono text-amber-400 bg-amber-500/10 px-1.5 py-0.5 rounded tabular-nums">{value}{unit}</span>
    </div>
    <input 
      type="range" 
      min={min} 
      max={max} 
      step={step} 
      value={value}
      onChange={(e) => onChange(parseFloat(e.target.value))}
      className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-amber-500 hover:accent-amber-400 transition-all"
    />
  </div>
);

const ColorPicker = ({ label, value, onChange }: any) => (
  <div className="flex justify-between items-center">
    <label className="text-[11px] font-medium text-slate-400">{label}</label>
    <div className="flex items-center gap-2">
      <span className="text-[10px] font-mono text-slate-500 uppercase">{value}</span>
      <input 
        type="color" 
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-5 h-5 rounded bg-transparent border-none cursor-pointer ring-1 ring-slate-700 overflow-hidden"
      />
    </div>
  </div>
);

const Toggle = ({ label, value, onChange }: any) => (
  <div className="flex justify-between items-center">
    <label className="text-[11px] font-medium text-slate-400">{label}</label>
    <button 
      onClick={() => onChange(!value)}
      className={`w-9 h-4.5 rounded-full transition-all relative cursor-pointer ${value ? 'bg-amber-600' : 'bg-slate-800'}`}
    >
      <div className={`absolute top-0.5 w-3.5 h-3.5 rounded-full bg-white transition-all shadow-sm ${value ? 'left-5' : 'left-0.5'}`} />
    </button>
  </div>
);

const LightsPanel: React.FC<LightsPanelProps> = ({ 
  lights, 
  onUpdateLights, 
  showHelpers, 
  onToggleHelpers,
  sceneAmbient,
  onUpdateSceneAmbient,
  envPreset,
  onUpdateEnvPreset
}) => {
  const addLight = (type: LightType) => {
    const newLight: LightSettings = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      color: '#ffffff',
      groundColor: type === 'hemisphere' ? '#3b82f6' : undefined,
      intensity: 1,
      position: [5, 5, 5],
      rotation: type === 'rectArea' ? [0, 0, 0] : undefined,
      width: type === 'rectArea' ? 4 : undefined,
      height: type === 'rectArea' ? 4 : undefined,
      castShadow: !['ambient', 'hemisphere', 'rectArea', 'lightProbe'].includes(type)
    };
    onUpdateLights([...lights, newLight]);
  };

  const removeLight = (id: string) => {
    onUpdateLights(lights.filter(l => l.id !== id));
  };

  const updateLight = (id: string, updates: Partial<LightSettings>) => {
    onUpdateLights(lights.map(l => l.id === id ? { ...l, ...updates } : l));
  };

  const envPresets = ['none', 'city', 'apartment', 'lobby', 'night', 'studio', 'warehouse', 'forest'];

  return (
    <div className="animate-in fade-in slide-in-from-right-4 duration-500 pb-10">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-xs font-black uppercase tracking-widest text-slate-500">Scene Lights</h2>
          <p className="text-[9px] text-slate-600 uppercase mt-1">Configure lighting layers</p>
        </div>
        <button 
          onClick={() => onToggleHelpers(!showHelpers)}
          className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border transition-all text-[10px] font-bold uppercase tracking-wider cursor-pointer ${
            showHelpers ? 'bg-amber-500/10 border-amber-500/50 text-amber-400' : 'bg-slate-800 border-slate-700 text-slate-500'
          }`}
        >
          {showHelpers ? <Eye size={12} /> : <EyeOff size={12} />}
          {showHelpers ? 'Helpers On' : 'Helpers Off'}
        </button>
      </div>

      {/* Global Defaults Section */}
      <ControlGroup title="Global Scene Defaults" icon={Globe}>
        <div className="space-y-6">
          <Slider 
            label="Base Ambient Intensity" 
            value={sceneAmbient} 
            min={0} 
            max={2} 
            step={0.1} 
            onChange={onUpdateSceneAmbient} 
          />
          <div className="space-y-2">
            <label className="text-[11px] font-medium text-slate-400">Environment Mapping</label>
            <div className="grid grid-cols-4 gap-1">
              {envPresets.map(p => (
                <button
                  key={p}
                  onClick={() => onUpdateEnvPreset(p)}
                  className={`py-1 text-[8px] font-bold uppercase rounded border transition-all cursor-pointer ${
                    envPreset === p ? 'bg-amber-600 border-amber-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-500'
                  }`}
                >
                  {p}
                </button>
              ))}
            </div>
          </div>
        </div>
      </ControlGroup>

      <div className="flex items-center gap-4 my-8">
        <div className="h-px flex-1 bg-slate-800" />
        <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">Dynamic Lights</span>
        <div className="h-px flex-1 bg-slate-800" />
      </div>

      <div className="grid grid-cols-3 gap-2 mb-8">
        {(['directional', 'point', 'spot', 'hemisphere', 'rectArea', 'ambient', 'lightProbe'] as LightType[]).map(type => (
          <button
            key={type}
            onClick={() => addLight(type)}
            className="flex flex-col items-center gap-2 p-3 bg-slate-800 hover:bg-amber-600/20 border border-slate-700 hover:border-amber-500/50 rounded-xl transition-all group cursor-pointer"
          >
            <Plus size={14} className="text-slate-500 group-hover:text-amber-400" />
            <span className="text-[8px] font-black uppercase tracking-tighter text-slate-400 group-hover:text-white truncate w-full text-center">{type}</span>
          </button>
        ))}
      </div>

      {lights.map((light, index) => (
        <ControlGroup 
          key={light.id} 
          title={`${light.type} Light`} 
          icon={Lightbulb}
          onRemove={() => removeLight(light.id)}
        >
          <div className="space-y-4">
            <ColorPicker 
              label={light.type === 'hemisphere' ? "Sky Color" : "Light Color"} 
              value={light.color} 
              onChange={(color: string) => updateLight(light.id, { color })} 
            />
            {light.type === 'hemisphere' && (
               <ColorPicker 
                label="Ground Color" 
                value={light.groundColor || '#000000'} 
                onChange={(groundColor: string) => updateLight(light.id, { groundColor })} 
              />
            )}
            <Slider 
              label="Intensity" 
              value={light.intensity} 
              min={0} 
              max={20} 
              step={0.1} 
              onChange={(intensity: number) => updateLight(light.id, { intensity })} 
            />
          </div>

          {light.type !== 'ambient' && (
            <>
              <div className="space-y-4 pt-4 border-t border-slate-800/50">
                <label className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Position (X, Y, Z)</label>
                <div className="grid grid-cols-3 gap-2">
                  {[0, 1, 2].map(axis => (
                    <div key={axis} className="flex flex-col gap-1">
                      <span className="text-[9px] text-slate-600 font-mono text-center uppercase">{['x', 'y', 'z'][axis]}</span>
                      <input 
                        type="number"
                        value={light.position[axis]}
                        onChange={(e) => {
                          const newPos = [...light.position] as [number, number, number];
                          newPos[axis] = parseFloat(e.target.value) || 0;
                          updateLight(light.id, { position: newPos });
                        }}
                        className="bg-slate-900 border border-slate-800 rounded px-2 py-1 text-[10px] font-mono text-amber-400 text-center focus:outline-none focus:border-amber-500/50"
                      />
                    </div>
                  ))}
                </div>
              </div>

              {light.type === 'rectArea' && (
                <div className="space-y-4 pt-4 border-t border-slate-800/50">
                   <Slider 
                    label="Width" 
                    value={light.width || 4} 
                    min={0.1} 
                    max={20} 
                    step={0.1} 
                    onChange={(width: number) => updateLight(light.id, { width })} 
                  />
                  <Slider 
                    label="Height" 
                    value={light.height || 4} 
                    min={0.1} 
                    max={20} 
                    step={0.1} 
                    onChange={(height: number) => updateLight(light.id, { height })} 
                  />
                </div>
              )}

              {!['hemisphere', 'rectArea', 'lightProbe'].includes(light.type) && (
                <div className="pt-4 border-t border-slate-800/50">
                  <Toggle 
                    label="Enable Shadow Mapping" 
                    value={light.castShadow} 
                    onChange={(castShadow: boolean) => updateLight(light.id, { castShadow })} 
                  />
                </div>
              )}
            </>
          )}
        </ControlGroup>
      ))}
    </div>
  );
};

export default LightsPanel;

