import SceneModel from './components/SceneModel';
import LightsPanel from './components/LightsPanel';
import EffectsPanel from './components/EffectsPanel';

// Initialize RectAreaLight uniforms
RectAreaLightUniformsLib.init();

const AmbientLightComp = 'ambientLight' as any;
const DirectionalLightComp = 'directionalLight' as any;
const PointLightComp = 'pointLight' as any;
const SpotLightComp = 'spotLight' as any;
const HemisphereLightComp = 'hemisphereLight' as any;
const RectAreaLightComp = 'rectAreaLight' as any;
const LightProbeComp = 'lightProbe' as any;
const OrthographicCameraComp = 'orthographicCamera' as any;
const GroupComp = 'group' as any;
const MeshComp = 'mesh' as any;
const PlaneGeometryComp = 'planeGeometry' as any;
const MeshStandardMaterialComp = 'meshStandardMaterial' as any;
const ColorComp = 'color' as any;

const DynamicLight: React.FC<{ light: LightSettings, globalShowHelpers: boolean }> = ({ light, globalShowHelpers }) => {
  const lightRef = useRef<any>(null);
  useHelper(globalShowHelpers && light.type === 'directional' ? lightRef : null, THREE.DirectionalLightHelper, 1, 'white');
  useHelper(globalShowHelpers && light.type === 'point' ? lightRef : null, THREE.PointLightHelper, 0.5, light.color);
  useHelper(globalShowHelpers && light.type === 'spot' ? lightRef : null, THREE.SpotLightHelper, 'white');
  useHelper(globalShowHelpers && light.type === 'hemisphere' ? lightRef : null, THREE.HemisphereLightHelper, 2, light.color);
  useHelper(globalShowHelpers && light.type === 'rectArea' ? lightRef : null, RectAreaLightHelper as any, 'white');
  useHelper(globalShowHelpers && light.showShadowHelper && lightRef.current?.shadow?.camera ? lightRef : null, THREE.CameraHelper);

  switch (light.type) {
    case 'directional':
      return (
        <DirectionalLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible}>
          <OrthographicCameraComp attach="shadow-camera" args={[-10, 10, 10, -10, 0.5, 30]} />
        </DirectionalLightComp>
      );
    case 'point':
      return <PointLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible} />;
    case 'spot':
      return <SpotLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible} angle={0.3} penumbra={1} />;
    case 'hemisphere':
      return <HemisphereLightComp ref={lightRef} position={light.position} args={[light.color, light.groundColor, light.intensity]} visible={light.visible} />;
    case 'rectArea':
      return <RectAreaLightComp ref={lightRef} position={light.position} rotation={light.rotation || [0, 0, 0]} intensity={light.intensity} width={light.width || 4} height={light.height || 4} color={light.color} visible={light.visible} />;
    case 'ambient':
      return <AmbientLightComp intensity={light.intensity} color={light.color} visible={light.visible} />;
    case 'lightProbe':
      return <LightProbeComp ref={lightRef} intensity={light.intensity} visible={light.visible} />;
    default: return null;
  }
};

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');
  const [customModel, setCustomModel] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const updateState = useCallback(<K extends keyof AppState, S extends keyof AppState[K]>(category: K, key: S, value: AppState[K][S]) => {
    setState(prev => ({ ...prev, [category]: { ...prev[category], [key]: value } }));
  }, []);

  const updateEffect = useCallback(<S extends keyof AppState['effects'], P extends keyof AppState['effects'][S]>(effect: S, prop: P, value: any) => {
    setState(prev => ({
      ...prev,
      effects: {
        ...prev.effects,
        [effect]: { ...prev.effects[effect], [prop]: value }
      }
    }));
  }, []);

  const updateMaterial = useCallback(<S extends keyof MaterialSettings>(key: S, value: MaterialSettings[S]) => {
    setState(prev => {
      const currentId = prev.selectedMaterialId;
      if (!prev.materials[currentId]) return prev;
      return {
        ...prev,
        materials: { ...prev.materials, [currentId]: { ...prev.materials[currentId], [key]: value } }
      };
    });
  }, []);

  const setTopState = useCallback(<K extends keyof AppState>(key: K, value: AppState[K]) => {
    setState(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);
      startTransition(() => {
        setCustomModel(url);
        setState(prev => ({ ...prev, scene: { ...prev.scene, modelType: 'custom' } }));
      });
    }
  };

  const onMaterialsDiscovered = useCallback((discoveredMaterials: string[]) => {
    setState(prev => {
      const newMaterials = { ...prev.materials };
      let firstId = prev.selectedMaterialId;
      discoveredMaterials.forEach((name, index) => {
        const id = `mat-${name || index}`;
        if (!newMaterials[id]) newMaterials[id] = createDefaultMaterial(id, name || `Material ${index + 1}`);
        if (index === 0 && (prev.selectedMaterialId === 'default-material' || !prev.materials[prev.selectedMaterialId])) firstId = id;
      });
      return { ...prev, materials: newMaterials, selectedMaterialId: firstId };
    });
  }, []);

  const handleUpdateLights = (lights: LightSettings[]) => setState(prev => ({ ...prev, lights }));

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".glb,.gltf,.obj" />
      <main className="relative flex-1 bg-black">
        {isPending && <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-50 pointer-events-none"><Loader2 className="w-10 h-10 text-blue-500 animate-spin" /></div>}
        <Canvas shadows={{ type: THREE.PCFSoftShadowMap }} dpr={[1, 2]} gl={{ antialias: true, alpha: false, stencil: false }}>
          <ColorComp attach="background" args={[state.scene.background]} />
          <PerspectiveCamera makeDefault position={[4, 3, 4]} fov={50} />
          <OrbitControls makeDefault autoRotate={state.scene.autoRotate} autoRotateSpeed={0.5} enableDamping />
          <AmbientLightComp intensity={state.scene.ambientIntensity} />
          {state.lights.map((light) => <DynamicLight key={light.id} light={light} globalShowHelpers={state.scene.showHelpers} />)}
          {state.scene.environmentPreset !== 'none' && <Environment preset={state.scene.environmentPreset as any} />}
          <GroupComp position={[0, 0, 0]}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <Suspense fallback={null}>
                <SceneModel materials={state.materials} modelType={state.scene.modelType} customUrl={customModel} override={state.scene.overrideMaterials} onMaterialsFound={onMaterialsDiscovered} />
              </Suspense>
            </Float>
          </GroupComp>
          {state.scene.showPlane && (
            <MeshComp rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.0, 0]} receiveShadow>
              <PlaneGeometryComp args={[100, 100]} />
              <MeshStandardMaterialComp color={state.scene.planeColor} roughness={state.scene.planeRoughness} metalness={0.1} transparent={state.scene.planeOpacity < 1} opacity={state.scene.planeOpacity} />
            </MeshComp>
          )}
          {state.scene.contactShadows && <ContactShadows position={[0, -0.99, 0]} opacity={state.scene.shadowOpacity} scale={15} blur={state.scene.shadowBlur} far={3} />}
          {state.scene.gridHelper && state.scene.showPlane && <Grid position={[0, -0.995, 0]} args={[20, 20]} sectionColor="#cbd5e1" cellColor="#94a3b8" fadeDistance={25} infiniteGrid />}
          <EffectComposer multisampling={4}>
            {state.effects.smaa.enabled && <SMAA />}
            {state.effects.fxaa.enabled && <FXAA />}
            {state.effects.bloom.enabled && <Bloom luminanceThreshold={state.effects.bloom.threshold} intensity={state.effects.bloom.intensity} radius={state.effects.bloom.radius} mipmapBlur />}
            {state.effects.glitch.enabled && <Glitch delay={state.effects.glitch.delay} duration={state.effects.glitch.duration} strength={state.effects.glitch.strength} mode={state.effects.glitch.mode} />}
            {state.effects.dotScreen.enabled && <DotScreen angle={state.effects.dotScreen.angle} scale={state.effects.dotScreen.scale} />}
            {state.effects.pixelation.enabled && <Pixelation granularity={state.effects.pixelation.granularity} />}
            {state.effects.halftone.enabled && <Halftone shape={state.effects.halftone.shape} radius={state.effects.halftone.radius} rotateR={state.effects.halftone.rotateR} rotateG={state.effects.halftone.rotateG} rotateB={state.effects.halftone.rotateB} scatter={state.effects.halftone.scatter} />}
            {state.effects.afterimage.enabled && <Afterimage damp={state.effects.afterimage.damp} />}
            {state.effects.depthOfField.enabled && <DepthOfField focusDistance={state.effects.depthOfField.focusDistance} focalLength={state.effects.depthOfField.focalLength} bokehScale={state.effects.depthOfField.bokehScale} height={state.effects.depthOfField.height} />}
            {state.effects.noise.enabled && <Noise opacity={state.effects.noise.opacity} />}
            {state.effects.vignette.enabled && <Vignette offset={state.effects.vignette.offset} darkness={state.effects.vignette.darkness} />}
            {state.effects.chromaticAberration.enabled && <ChromaticAberration offset={new THREE.Vector2(...state.effects.chromaticAberration.offset)} />}
            {state.effects.ssao.enabled && <SSAO samples={state.effects.ssao.samples} radius={state.effects.ssao.radius} intensity={state.effects.ssao.intensity} />}
            {state.effects.outline.enabled && <Outline edgeStrength={state.effects.outline.edgeStrength} pulseSpeed={state.effects.outline.pulseSpeed} visibleEdgeColor={parseInt(state.effects.outline.visibleEdgeColor.replace('#', '0x'))} hiddenEdgeColor={parseInt(state.effects.outline.hiddenEdgeColor.replace('#', '0x'))} />}
          </EffectComposer>
          <BakeShadows />
        </Canvas>
        <div className="absolute top-6 left-6 pointer-events-none select-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400">Three.js Master Control</h1>
          <p className="text-slate-500 text-[10px] tracking-[0.3em] uppercase mt-1 flex items-center gap-2"><Package size={10} /> {state.scene.modelType === 'custom' ? 'Complex Multi-Mesh Asset' : 'Internal Geometry'}</p>
        </div>
        <button onClick={() => fileInputRef.current?.click()} className="absolute bottom-6 left-6 p-4 bg-blue-600 hover:bg-blue-500 rounded-full shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all hover:scale-110 active:scale-95 group cursor-pointer" title="Upload GLB/OBJ"><Upload size={24} className="text-white" /></button>
      </main>
      <div className="w-[440px] h-full bg-slate-900/98 backdrop-blur-xl border-l border-slate-800 flex flex-col shadow-2xl z-10 overflow-hidden">
        <div className="flex border-b border-slate-800">
          <button onClick={() => setActiveTab('settings')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'settings' ? 'text-blue-400 border-blue-500 bg-slate-800/30' : 'text-slate-50 border-transparent hover:text-slate-300'}`}><Settings2 size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Props</span></button>
          <button onClick={() => setActiveTab('lights')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'lights' ? 'text-amber-400 border-amber-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Lightbulb size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Lights</span></button>
          <button onClick={() => setActiveTab('effects')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'effects' ? 'text-purple-400 border-purple-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Wand2 size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">FX</span></button>
          <button onClick={() => setActiveTab('code')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'code' ? 'text-emerald-400 border-emerald-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Code size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Code</span></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' && <Sidebar state={state} updateState={updateState} updateMaterial={updateMaterial} setSelectedMaterialId={(id) => setTopState('selectedMaterialId', id)} />}
          {activeTab === 'lights' && <LightsPanel lights={state.lights} onUpdateLights={handleUpdateLights} showHelpers={state.scene.showHelpers} onToggleHelpers={(v) => updateState('scene', 'showHelpers', v)} sceneAmbient={state.scene.ambientIntensity} onUpdateSceneAmbient={(v) => updateState('scene', 'ambientIntensity', v)} envPreset={state.scene.environmentPreset} onUpdateEnvPreset={(v) => updateState('scene', 'environmentPreset', v)} />}
          {activeTab === 'effects' && <EffectsPanel effects={state.effects} onUpdateEffect={updateEffect} />}
          {activeTab === 'code' && <CodePanel state={state} />}
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { AppState } from '../types';
import { Wand2, ChevronDown, ChevronUp, Zap, Radio, Grid3X3, Camera, Layers, Eye } from 'lucide-react';

interface EffectsPanelProps {
  effects: AppState['effects'];
  onUpdateEffect: (effect: keyof AppState['effects'], prop: string, value: any) => void;
}

const ControlGroup = ({ title, icon: Icon, enabled, onToggle, children }: any) => {
  const [isExpanded, setIsExpanded] = useState(enabled);
  return (
    <div className={`mb-4 rounded-xl border transition-all duration-300 ${enabled ? 'bg-slate-800/40 border-purple-500/50 shadow-lg shadow-purple-500/5' : 'bg-slate-900/40 border-slate-800 opacity-70'}`}>
      <div className="flex items-center justify-between p-4 cursor-pointer" onClick={() => setIsExpanded(!isExpanded)}>
        <div className="flex items-center gap-3">
          <div className={`p-1.5 rounded-lg transition-colors ${enabled ? 'bg-purple-500/20 text-purple-400' : 'bg-slate-800 text-slate-500'}`}>
            <Icon size={14} />
          </div>
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em]">{title}</h3>
        </div>
        <div className="flex items-center gap-3" onClick={e => e.stopPropagation()}>
          <button 
            onClick={onToggle} 
            className={`w-8 h-4 rounded-full transition-all relative cursor-pointer ${enabled ? 'bg-purple-600' : 'bg-slate-800'}`}
          >
            <div className={`absolute top-0.5 w-3 h-3 rounded-full bg-white transition-all ${enabled ? 'left-4.5' : 'left-0.5'}`} />
          </button>
          <div className="text-slate-600">
            {isExpanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          </div>
        </div>
      </div>
      {isExpanded && (
        <div className="p-4 pt-0 space-y-5 animate-in slide-in-from-top-2 duration-300">
          <div className="h-px bg-slate-800/50 mb-4" />
          {children}
        </div>
      )}
    </div>
  );
};

const Slider = ({ label, value, min, max, step, onChange, unit = "" }: any) => (
  <div className="group">
    <div className="flex justify-between items-center mb-1.5">
      <label className="text-[10px] font-bold text-slate-500 group-hover:text-slate-300 transition-colors uppercase tracking-widest">{label}</label>
      <span className="text-[10px] font-mono text-purple-400 tabular-nums">{Array.isArray(value) ? `${value[0].toFixed(2)}, ${value[1].toFixed(2)}` : `${value}${unit}`}</span>
    </div>
    <input 
      type="range" 
      min={min} 
      max={max} 
      step={step} 
      value={Array.isArray(value) ? value[0] : value}
      onChange={(e) => onChange(parseFloat(e.target.value))}
      className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-purple-500 hover:accent-purple-400 transition-all"
    />
  </div>
);

const ColorPicker = ({ label, value, onChange }: any) => (
  <div className="flex justify-between items-center">
    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{label}</label>
    <div className="flex items-center gap-2">
      <span className="text-[10px] font-mono text-slate-500 uppercase">{value}</span>
      <input 
        type="color" 
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-5 h-5 rounded bg-transparent border-none cursor-pointer ring-1 ring-slate-700 overflow-hidden"
      />
    </div>
  </div>
);

export default function EffectsPanel({ effects, onUpdateEffect }: EffectsPanelProps) {
  return (
    <div className="animate-in fade-in slide-in-from-right-4 duration-500 pb-10">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-xs font-black uppercase tracking-widest text-slate-500">Post-Processing</h2>
          <p className="text-[9px] text-slate-600 uppercase mt-1">Enhance visual fidelity</p>
        </div>
        <Wand2 size={16} className="text-purple-500 opacity-50" />
      </div>

      <ControlGroup title="Bloom" icon={Zap} enabled={effects.bloom.enabled} onToggle={() => onUpdateEffect('bloom', 'enabled', !effects.bloom.enabled)}>
        <Slider label="Intensity" value={effects.bloom.intensity} min={0} max={10} step={0.1} onChange={(v: any) => onUpdateEffect('bloom', 'intensity', v)} />
        <Slider label="Threshold" value={effects.bloom.threshold} min={0} max={1} step={0.01} onChange={(v: any) => onUpdateEffect('bloom', 'threshold', v)} />
        <Slider label="Radius" value={effects.bloom.radius} min={0} max={1} step={0.01} onChange={(v: any) => onUpdateEffect('bloom', 'radius', v)} />
      </ControlGroup>

      <ControlGroup title="Depth of Field" icon={Camera} enabled={effects.depthOfField.enabled} onToggle={() => onUpdateEffect('depthOfField', 'enabled', !effects.depthOfField.enabled)}>
        <Slider label="Focus Dist" value={effects.depthOfField.focusDistance} min={0} max={1} step={0.01} onChange={(v: any) => onUpdateEffect('depthOfField', 'focusDistance', v)} />
        <Slider label="Focal Length" value={effects.depthOfField.focalLength} min={0} max={0.1} step={0.001} onChange={(v: any) => onUpdateEffect('depthOfField', 'focalLength', v)} />
        <Slider label="Bokeh Scale" value={effects.depthOfField.bokehScale} min={0} max={10} step={0.1} onChange={(v: any) => onUpdateEffect('depthOfField', 'bokehScale', v)} />
      </ControlGroup>

      <ControlGroup title="Dot Screen" icon={Grid3X3} enabled={effects.dotScreen.enabled} onToggle={() => onUpdateEffect('dotScreen', 'enabled', !effects.dotScreen.enabled)}>
        <Slider label="Angle" value={effects.dotScreen.angle} min={0} max={Math.PI} step={0.01} onChange={(v: any) => onUpdateEffect('dotScreen', 'angle', v)} />
        <Slider label="Scale" value={effects.dotScreen.scale} min={0.1} max={5} step={0.1} onChange={(v: any) => onUpdateEffect('dotScreen', 'scale', v)} />
      </ControlGroup>

      <ControlGroup title="Pixelation" icon={Layers} enabled={effects.pixelation.enabled} onToggle={() => onUpdateEffect('pixelation', 'enabled', !effects.pixelation.enabled)}>
        <Slider label="Granularity" value={effects.pixelation.granularity} min={1} max={100} step={1} onChange={(v: any) => onUpdateEffect('pixelation', 'granularity', v)} />
      </ControlGroup>

      <ControlGroup title="Halftone" icon={Radio} enabled={effects.halftone.enabled} onToggle={() => onUpdateEffect('halftone', 'enabled', !effects.halftone.enabled)}>
        <Slider label="Radius" value={effects.halftone.radius} min={1} max={20} step={1} onChange={(v: any) => onUpdateEffect('halftone', 'radius', v)} />
        <Slider label="Scatter" value={effects.halftone.scatter} min={0} max={1} step={0.01} onChange={(v: any) => onUpdateEffect('halftone', 'scatter', v)} />
      </ControlGroup>

      <ControlGroup title="Glitch" icon={Zap} enabled={effects.glitch.enabled} onToggle={() => onUpdateEffect('glitch', 'enabled', !effects.glitch.enabled)}>
        <p className="text-[9px] text-slate-500 uppercase leading-relaxed mb-4">Random digital distortion and chromatic fringing.</p>
        <Slider label="Duration" value={effects.glitch.duration[0]} min={0.1} max={5} step={0.1} onChange={(v: any) => onUpdateEffect('glitch', 'duration', [v, v + 0.5])} />
      </ControlGroup>

      <ControlGroup title="Film Effects" icon={Camera} enabled={effects.noise.enabled} onToggle={() => onUpdateEffect('noise', 'enabled', !effects.noise.enabled)}>
        <Slider label="Grain Opacity" value={effects.noise.opacity} min={0} max={1} step={0.01} onChange={(v: any) => onUpdateEffect('noise', 'opacity', v)} />
        <Slider label="Vignette Offset" value={effects.vignette.offset} min={0} max={1} step={0.01} onChange={(v: any) => onUpdateEffect('vignette', 'offset', v)} />
        <Slider label="Vignette Dark" value={effects.vignette.darkness} min={0} max={1} step={0.01} onChange={(v: any) => onUpdateEffect('vignette', 'darkness', v)} />
      </ControlGroup>

      <ControlGroup title="Afterimage" icon={Eye} enabled={effects.afterimage.enabled} onToggle={() => onUpdateEffect('afterimage', 'enabled', !effects.afterimage.enabled)}>
        <Slider label="Dampening" value={effects.afterimage.damp} min={0} max={1} step={0.01} onChange={(v: any) => onUpdateEffect('afterimage', 'damp', v)} />
      </ControlGroup>

      <ControlGroup title="Antialiasing" icon={Layers} enabled={effects.smaa.enabled || effects.fxaa.enabled} onToggle={() => onUpdateEffect('smaa', 'enabled', !effects.smaa.enabled)}>
        <div className="flex gap-4">
          <button onClick={() => {onUpdateEffect('smaa', 'enabled', true); onUpdateEffect('fxaa', 'enabled', false);}} className={`flex-1 py-2 text-[8px] font-black uppercase rounded border transition-all ${effects.smaa.enabled ? 'bg-purple-600 border-purple-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>SMAA</button>
          <button onClick={() => {onUpdateEffect('fxaa', 'enabled', true); onUpdateEffect('smaa', 'enabled', false);}} className={`flex-1 py-2 text-[8px] font-black uppercase rounded border transition-all ${effects.fxaa.enabled ? 'bg-purple-600 border-purple-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>FXAA</button>
        </div>
      </ControlGroup>

      <ControlGroup title="Outline" icon={Layers} enabled={effects.outline.enabled} onToggle={() => onUpdateEffect('outline', 'enabled', !effects.outline.enabled)}>
        <ColorPicker label="Edge Color" value={effects.outline.visibleEdgeColor} onChange={(v: any) => onUpdateEffect('outline', 'visibleEdgeColor', v)} />
        <Slider label="Edge Strength" value={effects.outline.edgeStrength} min={1} max={10} step={0.1} onChange={(v: any) => onUpdateEffect('outline', 'edgeStrength', v)} />
      </ControlGroup>
    </div>
  );
}

import React from 'react';
import { AppState, MaterialSettings, MaterialType, ModelType } from '../types';
import { Palette, Box, Layers, MousePointer2, Sparkles, Target, Grid3X3 } from 'lucide-react';
import { MATERIAL_PRESETS_DATA } from '../constants';

interface SidebarProps {
  state: AppState;
  updateState: <K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => void;
  updateMaterial: <S extends keyof MaterialSettings>(key: S, value: MaterialSettings[S]) => void;
  setSelectedMaterialId: (id: string) => void;
}

const ControlGroup = ({ title, icon: Icon, children }: { title: string, icon: any, children?: React.ReactNode }) => (
  <div className="mb-10 last:mb-0">
    <div className="flex items-center gap-2 mb-5 text-slate-300">
      <div className="p-1.5 bg-slate-800 rounded-lg">
        <Icon size={14} className="text-blue-400" />
      </div>
      <h3 className="text-[10px] font-black uppercase tracking-[0.2em]">{title}</h3>
    </div>
    <div className="space-y-6">
      {children}
    </div>
  </div>
);

const Slider = ({ label, value, min, max, step, onChange, unit = "" }: any) => (
  <div className="group">
    <div className="flex justify-between items-center mb-1.5">
      <label className="text-[11px] font-medium text-slate-400 group-hover:text-slate-200 transition-colors">{label}</label>
      <span className="text-[10px] font-mono text-blue-400 bg-blue-500/10 px-1.5 py-0.5 rounded tabular-nums">{value}{unit}</span>
    </div>
    <input 
      type="range" 
      min={min} 
      max={max} 
      step={step} 
      value={value}
      onChange={(e) => onChange(parseFloat(e.target.value))}
      className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 transition-all"
    />
  </div>
);

const ColorPicker = ({ label, value, onChange }: any) => (
  <div className="flex justify-between items-center">
    <label className="text-[11px] font-medium text-slate-400">{label}</label>
    <div className="flex items-center gap-2">
      <span className="text-[10px] font-mono text-slate-500 uppercase">{value}</span>
      <input 
        type="color" 
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-5 h-5 rounded bg-transparent border-none cursor-pointer ring-1 ring-slate-700 overflow-hidden"
      />
    </div>
  </div>
);

const Toggle = ({ label, value, onChange }: any) => (
  <div className="flex justify-between items-center">
    <label className="text-[11px] font-medium text-slate-400">{label}</label>
    <button 
      onClick={() => onChange(!value)}
      className={`w-9 h-4.5 rounded-full transition-all relative cursor-pointer ${value ? 'bg-blue-600' : 'bg-slate-800'}`}
    >
      <div className={`absolute top-0.5 w-3.5 h-3.5 rounded-full bg-white transition-all shadow-sm ${value ? 'left-5' : 'left-0.5'}`} />
    </button>
  </div>
);

const Sidebar: React.FC<SidebarProps> = ({ state, updateState, updateMaterial, setSelectedMaterialId }) => {
  const activeMat = (state.materials[state.selectedMaterialId] || Object.values(state.materials)[0]) as MaterialSettings | undefined;

  const applyPreset = (presetData: any) => {
    Object.entries(presetData).forEach(([key, value]) => {
      updateMaterial(key as any, value as any);
    });
  };

  const materialTypes: MaterialType[] = ['basic', 'phong', 'lambert', 'standard', 'physical', 'toon', 'normal', 'depth', 'matcap'];
  const modelTypes: ModelType[] = ['icosahedron', 'sphere', 'box', 'torus', 'cylinder', 'cone', 'knot'];

  if (!activeMat) return <div className="text-slate-500 text-xs py-10 text-center">Initializing...</div>;

  const supportsColor = activeMat.type !== 'normal' && activeMat.type !== 'depth';
  const supportsEmissive = ['phong', 'lambert', 'standard', 'physical'].includes(activeMat.type);
  const supportsSpecular = activeMat.type === 'phong';
  const supportsPBR = ['standard', 'physical'].includes(activeMat.type);
  const supportsClearcoat = activeMat.type === 'physical';

  return (
    <div className="animate-in fade-in slide-in-from-right-4 duration-500 pb-10">
      <ControlGroup title="Model Geometry" icon={Box}>
        <div className="grid grid-cols-4 gap-2">
          {modelTypes.map((type) => (
            <button
              key={type}
              onClick={() => updateState('scene', 'modelType', type)}
              className={`py-2 text-[8px] font-bold uppercase rounded-lg border transition-all cursor-pointer ${
                state.scene.modelType === type 
                ? 'bg-blue-600 border-blue-500 text-white shadow-lg' 
                : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'
              }`}
            >
              {type}
            </button>
          ))}
        </div>
      </ControlGroup>

      <div className="h-px bg-slate-800/50 my-8" />

      <ControlGroup title="Material Focus" icon={Target}>
        <div className="space-y-3">
          <label className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Select Sub-Material</label>
          <select 
            value={state.selectedMaterialId}
            onChange={(e) => setSelectedMaterialId(e.target.value)}
            className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs py-2 px-3 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all cursor-pointer"
          >
            {(Object.entries(state.materials) as [string, MaterialSettings][]).map(([id, mat]) => (
              <option key={id} value={id}>{mat.name}</option>
            ))}
          </select>
          <Toggle 
            label="Override GLTF materials" 
            value={state.scene.overrideMaterials} 
            onChange={(v: boolean) => updateState('scene', 'overrideMaterials', v)} 
          />
        </div>
      </ControlGroup>

      <div className="h-px bg-slate-800/50 my-8" />

      <ControlGroup title="Material Engine" icon={MousePointer2}>
        <div className="grid grid-cols-3 gap-1 bg-slate-800 p-1 rounded-lg mb-6">
          {materialTypes.map((t) => (
            <button
              key={t}
              onClick={() => updateMaterial('type', t)}
              className={`py-1.5 text-[8px] font-black uppercase rounded transition-all cursor-pointer ${
                activeMat.type === t ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
              }`}
            >
              {t}
            </button>
          ))}
        </div>
        <div className="grid grid-cols-2 gap-2">
          {Object.entries(MATERIAL_PRESETS_DATA).map(([name, data]) => (
            <button
              key={name}
              onClick={() => applyPreset(data)}
              className="px-3 py-2 text-[9px] font-bold bg-slate-800 hover:bg-blue-600/20 border border-slate-700 hover:border-blue-500/50 rounded-lg transition-all text-slate-400 hover:text-white cursor-pointer"
            >
              {name}
            </button>
          ))}
        </div>
      </ControlGroup>

      <div className="h-px bg-slate-800/50 my-8" />

      <ControlGroup title="Visual Properties" icon={Palette}>
        {supportsColor && (
          <ColorPicker label="Base Color" value={activeMat.color} onChange={(v: string) => updateMaterial('color', v)} />
        )}

        {supportsEmissive && (
          <div className="space-y-6 pt-4 border-t border-slate-800/50">
            <ColorPicker label="Emissive" value={activeMat.emissive} onChange={(v: string) => updateMaterial('emissive', v)} />
            <Slider label="Emissive Intensity" value={activeMat.emissiveIntensity} min={0} max={100} step={1} onChange={(v: number) => updateMaterial('emissiveIntensity', v)} />
          </div>
        )}

        {supportsSpecular && (
          <div className="space-y-6 pt-4 border-t border-slate-800">
            <h4 className="text-[9px] text-blue-400 uppercase font-black tracking-widest flex items-center gap-2">
               <Sparkles size={10} /> Phong Highlights
            </h4>
