      const data = JSON.parse(response.text || '{}');

      setState(prev => ({
        ...prev,
        scene: {
          ...prev.scene,
          background: data.scene.background || prev.scene.background,
          ambientIntensity: data.scene.ambientIntensity ?? prev.scene.ambientIntensity,
